"""Signal scanning and flow analysis framework."""

# ========================================================================
# src/signals/flow_analyzer.py
# ========================================================================

"""Generic trade-flow pattern detection framework.

This module is an **observational** layer. It detects patterns in the
market trade tape (repeated sizes, directional flow, trades near local
extrema) and returns an ephemeral ``FlowReport``. It never alters
strategy behaviour, fair-value estimates, or execution decisions.

Persisted state (via ``ProductMemory``) is kept to the absolute minimum
needed for cross-call continuity:

- ``values["scan_flow_score"]`` — decayed directional score in [-1, 1].
- ``counters["scan_step_count"]`` — number of steps the scanner has run.

Extrema (high / low) are derived from ``memory.recent_mids`` each step
and are **not** persisted.

Net-flow convention (heuristic, not true aggressor inference):
- Trade with only ``buyer`` populated → +quantity (buy pressure proxy).
- Trade with only ``seller`` populated -> -quantity (sell pressure proxy).
- Trade with both or neither → 0 (ambiguous, excluded from flow).
"""




# ---------------------------------------------------------------- keys

_KEY_FLOW_SCORE = "scan_flow_score"
_KEY_STEP_COUNT = "scan_step_count"


class FlowAnalyzer:
    """Stateless scanner — all mutable state lives in ``ProductMemory``."""

    def __init__(self, config: ScannerConfig) -> None:
        self.config = config

    # -------------------------------------------------------------- public

    def scan(
        self,
        snapshot: NormalizedSnapshot,
        memory: ProductMemory,
    ) -> FlowReport | None:
        """Analyse the current step's trade tape and return a report.

        Returns ``None`` when the scanner is disabled so the caller can
        skip any downstream logging unconditionally.
        """
        if not self.config.enabled:
            return None

        market_trades = tuple(t for t in snapshot.trades if t.source == "market")

        repeated_sizes = _count_sizes(market_trades)
        net_flow = _compute_net_flow(market_trades)
        total_volume = sum(t.quantity for t in market_trades) or 1

        old_score = memory.values.get(_KEY_FLOW_SCORE, 0.0)
        normalised = max(-1.0, min(1.0, net_flow / total_volume))
        new_score = self.config.flow_decay * old_score + (1.0 - self.config.flow_decay) * normalised
        new_score = max(-1.0, min(1.0, new_score))

        recent_high, recent_low = _derive_extrema(memory.recent_mids, self.config.extrema_window)
        near_high = _any_near(market_trades, recent_high, self.config.extrema_tolerance)
        near_low = _any_near(market_trades, recent_low, self.config.extrema_tolerance)

        flags = _build_flags(
            repeated_sizes=repeated_sizes,
            flow_score=new_score,
            near_high=near_high,
            near_low=near_low,
            threshold=self.config.repeated_size_threshold,
        )

        # Persist minimal state -------------------------------------------
        memory.values[_KEY_FLOW_SCORE] = new_score
        memory.counters[_KEY_STEP_COUNT] = memory.counters.get(_KEY_STEP_COUNT, 0) + 1

        return FlowReport(
            product=snapshot.product,
            timestamp=snapshot.timestamp,
            repeated_sizes=MappingProxyType(repeated_sizes),
            net_flow=net_flow,
            flow_score=round(new_score, 6),
            near_high=near_high,
            near_low=near_low,
            flags=flags,
            metadata=MappingProxyType(
                {
                    "market_trade_count": len(market_trades),
                    "total_volume": total_volume,
                }
            ),
        )


# -------------------------------------------------------------- helpers


def _count_sizes(trades: tuple[TradePrint, ...]) -> dict[int, int]:
    """Count how many times each trade quantity appears."""
    return dict(Counter(t.quantity for t in trades))


def _compute_net_flow(trades: tuple[TradePrint, ...]) -> int:
    """Heuristic signed net volume.

    This is a *proxy* for directional pressure — it does not claim to
    infer the true aggressor side. The convention is intentionally
    conservative: ambiguous trades (both buyer and seller populated, or
    neither) contribute zero.
    """
    net = 0
    for t in trades:
        has_buyer = t.buyer is not None and t.buyer != ""
        has_seller = t.seller is not None and t.seller != ""
        if has_buyer and not has_seller:
            net += t.quantity
        elif has_seller and not has_buyer:
            net -= t.quantity
        # both or neither → ambiguous, skip
    return net


def _derive_extrema(recent_mids: list[float], window: int) -> tuple[float | None, float | None]:
    """Return (high, low) from the last *window* mid prices, or None."""
    if not recent_mids:
        return None, None
    tail = recent_mids[-window:] if window > 0 else recent_mids
    return max(tail), min(tail)


def _any_near(
    trades: tuple[TradePrint, ...],
    level: float | None,
    tolerance: float,
) -> bool:
    """True if any trade price is within *tolerance* of *level*."""
    if level is None or not trades:
        return False
    return any(abs(t.price - level) <= tolerance for t in trades)


def _build_flags(
    *,
    repeated_sizes: dict[int, int],
    flow_score: float,
    near_high: bool,
    near_low: bool,
    threshold: int,
) -> tuple[str, ...]:
    """Build a tuple of human-readable pattern labels."""
    flags: list[str] = []

    for qty, count in sorted(repeated_sizes.items()):
        if count >= threshold:
            flags.append(f"repeated_size_{qty}x{count}")

    if flow_score > 0.5:
        flags.append("buy_pressure")
    elif flow_score < -0.5:
        flags.append("sell_pressure")

    if near_high:
        flags.append("near_local_high")
    if near_low:
        flags.append("near_local_low")

    return tuple(flags)

# ========================================================================
# src/core/signals.py
# ========================================================================

"""Translate fair value + snapshot + config into a trading intent.

This module converts "what do we believe" (the fair value estimate)
into "what would we want to do about it" (a ``SignalIntent`` naming
taker thresholds, maker prices, and the execution mode). It deliberately
does NOT emit ``Order``s — that's the execution engine's job.

Capacity recovery rule:
- When ``|position / limit| >= flatten_threshold`` the engine enters
  "recovery" mode. It stops adding to the side that already has
  exposure and tightens the opposite side toward fair value.
- In practice that means a long position disables buy intent entirely
  (maker bid size = 0 AND taker ``buy_below`` is set to ``None``) and
  pulls the maker ask in to fair value so inventory unwinds fastest.

Phase-9 early-window extensions:
- ``early_window`` gates the "early" branches by ``snapshot.timestamp``.
- When set, ``taker_edge_buy`` / ``taker_edge_sell`` split the normally
  symmetric taker threshold (useful when the day has a directional
  drift). Their ``early_*`` siblings only apply in the early window.
- ``early_short_cap`` blocks sell intent entirely while short inventory
  is at or below the cap (Family 2 — hard first-half short guard).
- ``early_short_skew_mult`` + ``early_short_flatten`` give a stricter
  recovery profile while short during the early window (Family 4).

All Phase-9 knobs default to neutral values. With defaults, this
module's output is byte-identical to the Phase-8 behavior.
"""





def _effective_taker_edges(
    config: ProductConfig,
    *,
    in_early_window: bool,
) -> tuple[float, float]:
    """Resolve (buy_edge, sell_edge) with per-side / early overrides.

    Resolution order per side:
    1. If in the early window and the ``early_taker_edge_<side>`` is set,
       use it.
    2. Else if the full-day ``taker_edge_<side>`` is set, use it.
    3. Else fall back to the symmetric ``taker_edge``.
    """
    buy = config.taker_edge_buy if config.taker_edge_buy is not None else config.taker_edge
    sell = config.taker_edge_sell if config.taker_edge_sell is not None else config.taker_edge
    if in_early_window:
        if config.early_taker_edge_buy is not None:
            buy = config.early_taker_edge_buy
        if config.early_taker_edge_sell is not None:
            sell = config.early_taker_edge_sell
    return buy, sell


class SignalEngine:
    def build_market_making_intent(
        self,
        product: str,
        snapshot: NormalizedSnapshot,
        fair_value: FairValueEstimate,
        config: ProductConfig,
    ) -> SignalIntent:
        in_early_window = (
            config.early_window > 0 and snapshot.timestamp < config.early_window
        )
        buy_taker_edge, sell_taker_edge = _effective_taker_edges(
            config, in_early_window=in_early_window
        )

        position_ratio = snapshot.position / config.position_limit if config.position_limit else 0.0

        # Skew normally scales linearly with inventory ratio. In the
        # early window while short we can amplify (Family 4) to pull
        # back toward flat faster.
        skew_multiplier = 1.0
        if in_early_window and snapshot.position < 0 and config.early_short_skew_mult != 1.0:
            skew_multiplier = config.early_short_skew_mult
        skew = position_ratio * config.inventory_skew * skew_multiplier

        # Flatten threshold: allow a stricter short-side flatten during
        # the early window (Family 4). Long side and non-early behavior
        # are unchanged.
        effective_flatten = config.flatten_threshold
        if (
            in_early_window
            and snapshot.position < 0
            and config.early_short_flatten is not None
        ):
            effective_flatten = config.early_short_flatten
        flattening = abs(position_ratio) >= effective_flatten

        buy_below: float | None = fair_value.price - buy_taker_edge - skew
        sell_above: float | None = fair_value.price + sell_taker_edge - skew

        raw_bid = math.floor(fair_value.price - config.maker_edge - skew)
        raw_ask = math.ceil(fair_value.price + config.maker_edge - skew)

        if snapshot.best_ask is not None:
            raw_bid = min(raw_bid, snapshot.best_ask.price - config.tick_size)
        if snapshot.best_bid is not None:
            raw_ask = max(raw_ask, snapshot.best_bid.price + config.tick_size)

        bid_size = config.quote_size
        ask_size = config.quote_size
        mode: ExecutionMode = "hybrid"
        rationale = "market_make_around_fair_value"

        if flattening:
            mode = "recovery"
            rationale = "inventory_recovery"
            if snapshot.position > 0:
                # Long: stop buying entirely, pull ask toward fair value.
                bid_size = 0
                buy_below = None
                raw_ask = min(raw_ask, math.floor(fair_value.price))
            elif snapshot.position < 0:
                # Short: stop selling entirely, pull bid toward fair value.
                ask_size = 0
                sell_above = None
                raw_bid = max(raw_bid, math.ceil(fair_value.price))

        # Family 2 — early short-cap. Enforced *after* normal recovery
        # so we don't fight the recovery logic when the position is
        # already above the cap. Effect: once the net short has reached
        # the cap inside the early window, both taker-sell and maker-
        # ask are disabled until the cap is no longer breached (either
        # time passes out of the early window or inventory recovers).
        if (
            in_early_window
            and config.early_short_cap is not None
            and snapshot.position <= config.early_short_cap
        ):
            sell_above = None
            ask_size = 0
            if mode != "recovery":
                mode = "recovery"
                rationale = "early_short_cap"

        quote = QuoteIntent(
            bid_price=raw_bid if bid_size > 0 else None,
            bid_size=bid_size,
            ask_price=raw_ask if ask_size > 0 else None,
            ask_size=ask_size,
        )

        return SignalIntent(
            product=product,
            fair_value=fair_value,
            mode=mode,
            buy_below=buy_below,
            sell_above=sell_above,
            quote=quote,
            rationale=rationale,
            metadata={
                "position_ratio": round(position_ratio, 4),
                "skew": round(skew, 4),
                "flattening": flattening,
                "in_early_window": in_early_window,
            },
        )

# ========================================================================
# src/core/execution.py
# ========================================================================

class ExecutionEngine:
    def generate_orders(
        self,
        snapshot: NormalizedSnapshot,
        intent: SignalIntent,
        config: ProductConfig,
    ) -> list[Order]:
        orders: list[Order] = []

        remaining_buy = config.max_aggressive_size
        remaining_sell = config.max_aggressive_size

        if intent.buy_below is not None:
            for ask in snapshot.asks:
                if ask.price > intent.buy_below or remaining_buy <= 0:
                    break
                quantity = min(ask.volume, remaining_buy)
                if quantity > 0:
                    orders.append(Order(snapshot.product, ask.price, quantity))
                    remaining_buy -= quantity

        if intent.sell_above is not None:
            for bid in snapshot.bids:
                if bid.price < intent.sell_above or remaining_sell <= 0:
                    break
                quantity = min(bid.volume, remaining_sell)
                if quantity > 0:
                    orders.append(Order(snapshot.product, bid.price, -quantity))
                    remaining_sell -= quantity

        if intent.quote is not None:
            if intent.quote.bid_price is not None and intent.quote.bid_size > 0:
                orders.append(
                    Order(snapshot.product, intent.quote.bid_price, intent.quote.bid_size)
                )
            if intent.quote.ask_price is not None and intent.quote.ask_size > 0:
                orders.append(
                    Order(snapshot.product, intent.quote.ask_price, -intent.quote.ask_size)
                )

        return orders

# ========================================================================
# src/core/risk.py
# ========================================================================

"""Per-product position legality and clipping.

This is the single place where we enforce Prosperity's hard position
limits. Strategies must never assume their orders are final: the risk
manager always owns the decision about what quantity actually leaves the
trader.

The clipping model:
- We compute remaining buy and sell capacity from the current position
  and the product's limit.
- We walk through the strategy's orders in submission order, reducing
  each to fit the remaining capacity on that side.
- Orders that would have zero quantity after clipping are dropped.
- Zero-quantity input orders are silently dropped.
- An order whose ``symbol`` does not match the product being clipped is
  a programming error and raises ``ValueError`` immediately.

The rationale for clipping per-side instead of per-order is that
Prosperity will reject an entire side if the aggregate would breach the
limit. By aggregating capacity here, we make the exchange reject nothing.
"""





@dataclass(frozen=True)
class Capacity:
    buy: int
    sell: int


class RiskManager:
    @staticmethod
    def remaining_buy_capacity(position: int, limit: int) -> int:
        if limit < 0:
            raise ValueError("limit must be >= 0")
        return max(0, limit - position)

    @staticmethod
    def remaining_sell_capacity(position: int, limit: int) -> int:
        if limit < 0:
            raise ValueError("limit must be >= 0")
        return max(0, limit + position)

    @classmethod
    def capacity(cls, position: int, limit: int) -> Capacity:
        return Capacity(
            buy=cls.remaining_buy_capacity(position, limit),
            sell=cls.remaining_sell_capacity(position, limit),
        )

    @staticmethod
    def inventory_ratio(position: int, limit: int) -> float:
        if limit <= 0:
            return 0.0
        return position / limit

    def clip_orders(
        self,
        product: str,
        orders: list[Order],
        current_position: int,
        limit: int,
    ) -> list[Order]:
        if limit < 0:
            raise ValueError("limit must be >= 0")

        buy_capacity = self.remaining_buy_capacity(current_position, limit)
        sell_capacity = self.remaining_sell_capacity(current_position, limit)
        clipped: list[Order] = []

        for order in orders:
            if order.symbol != product:
                raise ValueError(
                    f"risk.clip_orders: order symbol {order.symbol!r} does not "
                    f"match product {product!r}"
                )
            if order.quantity == 0:
                continue

            if order.quantity > 0:
                quantity = min(order.quantity, buy_capacity)
                if quantity > 0:
                    clipped.append(Order(order.symbol, order.price, quantity))
                    buy_capacity -= quantity
            else:
                quantity = min(-order.quantity, sell_capacity)
                if quantity > 0:
                    clipped.append(Order(order.symbol, order.price, -quantity))
                    sell_capacity -= quantity

        return clipped

# ========================================================================
# src/core/residual.py
# ========================================================================

"""Optional residual capacity utilizer (framework-only, ships disabled).

After the main strategy emits orders, there is often unused position
budget on one or both sides.  This module inspects the leftover capacity
and optionally appends small passive maker orders to capture spread from
the residual room.

Hard rules enforced here:

1. **Maker-only** -- residual orders never cross the spread.
2. **No duplicate prices** -- if the main strategy already placed an
   order on the same side at the exact price the residual would use,
   the residual order on that side is suppressed.
3. **Post-processing only, zero coupling** -- the module receives the
   main strategy's raw order list as read-only input and appends to it.
   It never modifies existing orders, never reads or writes strategy /
   signal / fair-value state.
4. **Default disabled** -- ``ResidualConfig.enabled`` is ``False``.
   The enablement gate (PnL, trade count, maker/taker mix, markouts,
   time-near-limits comparison) must pass before the flag is flipped.

Design:
- Runs after ``ExecutionEngine.generate_orders()`` and before
  ``RiskManager.clip_orders()``.
- The risk manager still clips the combined list, so this module
  cannot breach position limits.
"""





class ResidualAllocator:
    """Append small passive orders into unused position capacity."""

    def __init__(self, config: ResidualConfig) -> None:
        self._config = config

    def augment_orders(
        self,
        *,
        product: str,
        orders: list[Order],
        snapshot: NormalizedSnapshot,
        fair_value: float,
        position: int,
        limit: int,
        mode: ExecutionMode = "maker",
    ) -> list[Order]:
        """Return *orders* with optional residual orders appended.

        If the module is disabled or the strategy is in recovery mode,
        returns the input list unchanged.
        """
        if not self._config.enabled:
            return orders

        # Never add residual orders during recovery (flattening).
        if mode == "recovery":
            return orders

        buy_capacity = max(0, limit - position)
        sell_capacity = max(0, limit + position)

        # Subtract capacity already consumed by main orders.
        # Also collect main-strategy prices per side for duplicate guard.
        main_bid_prices: set[int] = set()
        main_ask_prices: set[int] = set()

        for order in orders:
            if order.quantity > 0:
                buy_capacity -= order.quantity
                main_bid_prices.add(order.price)
            elif order.quantity < 0:
                sell_capacity -= abs(order.quantity)
                main_ask_prices.add(order.price)

        buy_capacity = max(0, buy_capacity)
        sell_capacity = max(0, sell_capacity)

        residual_orders: list[Order] = []

        if buy_capacity > 0:
            bid_price = math.floor(fair_value - self._config.residual_edge)
            bid_size = min(self._config.residual_size, buy_capacity)

            # Spread guard: suppress if bid would cross or touch best ask.
            best_ask = snapshot.best_ask
            crosses_spread = best_ask is not None and bid_price >= best_ask.price

            # Duplicate-price guard.
            duplicates_main = bid_price in main_bid_prices

            if bid_size > 0 and not crosses_spread and not duplicates_main:
                residual_orders.append(Order(product, bid_price, bid_size))

        if sell_capacity > 0:
            ask_price = math.ceil(fair_value + self._config.residual_edge)
            ask_size = min(self._config.residual_size, sell_capacity)

            # Spread guard: suppress if ask would cross or touch best bid.
            best_bid = snapshot.best_bid
            crosses_spread = best_bid is not None and ask_price <= best_bid.price

            # Duplicate-price guard.
            duplicates_main = ask_price in main_ask_prices

            if ask_size > 0 and not crosses_spread and not duplicates_main:
                residual_orders.append(Order(product, ask_price, -ask_size))

        if not residual_orders:
            return orders

        return [*orders, *residual_orders]

