# ========================================================================
# src/core/primitives/crash_telemetry.py
# ========================================================================

"""Crash telemetry + kill-switch primitive.

Replaces the silent-exception-swallow pattern in ``trader.run()``. When
a strategy raises:

1. **Log loudly** — stderr traceback with product + tick context so the
   error isn't hidden under an empty-orders return.

2. **Persist an error breadcrumb** — append an error summary to
   ``EngineState.errors`` deque so subsequent ticks can see the history.

3. **Fire a kill-switch** — if the error rate exceeds threshold (default
   3 errors per 100 ticks), force all strategies into ``recovery`` mode
   for a cool-off window.

4. **Expose a heartbeat** — ``last_successful_tick`` lets external
   observers detect a silent hang where the strategy returned empty
   orders without raising (the R1/R2 silent-degradation failure mode).

The primitive is designed to wrap the strategy dispatch loop, not to
replace the existing ``trader.py`` top-level safety net entirely
(Prosperity's container must not crash). Belt-and-suspenders: the
inner crash-telemetry surfaces errors; the outer safety net prevents
container kills.
"""



_LOG = logging.getLogger(__name__)

T = TypeVar("T")


@dataclass(frozen=True)
class CrashTelemetryConfig:
    """Crash-telemetry + kill-switch tuning."""

    enabled: bool = True

    # Error history retained in EngineState for diagnosis.
    max_error_history: int = 32

    # Kill-switch: if errors in the last N ticks exceed threshold, halt.
    kill_window_ticks: int = 100
    kill_threshold: int = 3
    """Halt all strategies if >= this many errors occur in kill_window_ticks."""

    # Cool-off: once kill-switch fires, force recovery mode for this many ticks.
    cooloff_ticks: int = 500

    # Whether to also trip on "silent" hangs (strategy returned zero orders
    # for N consecutive ticks on a non-zero book). Separate from errors.
    hang_threshold: int = 1000

    def __post_init__(self) -> None:
        if self.max_error_history <= 0:
            raise ValueError("max_error_history must be > 0")
        if self.kill_window_ticks <= 0:
            raise ValueError("kill_window_ticks must be > 0")
        if self.kill_threshold <= 0:
            raise ValueError("kill_threshold must be > 0")


@dataclass
class CrashTelemetryState:
    """Mutable state persisted across ticks (serializes into traderData).

    Separate from the static config so we can snapshot/restore it via
    the existing StateStore mechanism without breaking the frozen-config
    invariant.
    """

    # (tick, product, error_class, short_message) tuples.
    recent_errors: deque[tuple[int, str, str, str]] = field(default_factory=deque)

    # Count of ticks since last error that caused a halt; for cool-off.
    cooloff_remaining: int = 0

    # Tick number of the last tick where *any* strategy returned >= 1 order.
    last_successful_tick: int = -1

    # Count of consecutive silent ticks (zero orders on a non-empty book).
    silent_streak: int = 0

    def record_error(
        self,
        tick: int,
        product: str,
        error_class: str,
        message: str,
        max_history: int,
    ) -> None:
        self.recent_errors.append((tick, product, error_class, message[:200]))
        while len(self.recent_errors) > max_history:
            self.recent_errors.popleft()

    def errors_in_window(self, current_tick: int, window: int) -> int:
        threshold_tick = current_tick - window
        return sum(1 for t, *_ in self.recent_errors if t >= threshold_tick)

    def is_halted(self) -> bool:
        return self.cooloff_remaining > 0

    def start_cooloff(self, ticks: int) -> None:
        self.cooloff_remaining = max(self.cooloff_remaining, ticks)

    def tick_cooloff(self) -> None:
        if self.cooloff_remaining > 0:
            self.cooloff_remaining -= 1


# ============================================================= API


def run_with_telemetry(
    operation: Callable[[], T],
    *,
    tick: int,
    product: str,
    state: CrashTelemetryState,
    config: CrashTelemetryConfig,
    default: T,
) -> tuple[T, bool]:
    """Execute ``operation()``, catching errors and updating telemetry.

    Returns ``(result_or_default, raised)``. If ``raised`` is True,
    ``result_or_default`` is ``default`` (the fallback) and the error
    has been logged + persisted.

    If the kill-switch fires (threshold exceeded in window), the
    telemetry state starts a cool-off; the caller should check
    ``state.is_halted()`` on subsequent ticks to decide whether to
    suppress strategy dispatch entirely.
    """
    if not config.enabled:
        try:
            return operation(), False
        except Exception:  # noqa: BLE001 — telemetry disabled, re-raise is unsafe
            raise

    try:
        result = operation()
        state.tick_cooloff()
        return result, False
    except Exception as exc:  # noqa: BLE001 — we want every error caught
        error_class = type(exc).__name__
        message = str(exc)
        # Stderr traceback — loud, visible in container logs.
        traceback.print_exc(file=sys.stderr)
        _LOG.error(
            "crash_telemetry: tick=%d product=%s error=%s msg=%s",
            tick, product, error_class, message,
        )
        state.record_error(tick, product, error_class, message, config.max_error_history)

        # Kill-switch evaluation.
        error_count = state.errors_in_window(tick, config.kill_window_ticks)
        if error_count >= config.kill_threshold:
            _LOG.error(
                "crash_telemetry: KILL-SWITCH TRIGGERED — %d errors in last %d ticks "
                "(threshold %d); entering %d-tick cool-off",
                error_count, config.kill_window_ticks, config.kill_threshold,
                config.cooloff_ticks,
            )
            state.start_cooloff(config.cooloff_ticks)

        state.tick_cooloff()
        return default, True


def update_heartbeat(
    *,
    tick: int,
    orders_emitted: int,
    has_non_empty_book: bool,
    state: CrashTelemetryState,
    hang_threshold: int,
) -> bool:
    """Update hang-detection heartbeat. Returns True if a hang is detected.

    A "hang" is a long stretch of silent ticks (zero orders) on a
    non-empty book — the failure mode where our safety net silently
    swallows an exception every tick.
    """
    if orders_emitted > 0:
        state.last_successful_tick = tick
        state.silent_streak = 0
        return False
    if has_non_empty_book:
        state.silent_streak += 1
    if state.silent_streak >= hang_threshold:
        _LOG.error(
            "crash_telemetry: HANG DETECTED — %d consecutive silent ticks on "
            "non-empty book. last_success=%d current=%d",
            state.silent_streak, state.last_successful_tick, tick,
        )
        return True
    return False


def snapshot_telemetry(state: CrashTelemetryState) -> dict:
    """Serializable dict for inclusion in ``traderData`` or logger events."""
    return {
        "recent_errors": list(state.recent_errors),
        "cooloff_remaining": state.cooloff_remaining,
        "last_successful_tick": state.last_successful_tick,
        "silent_streak": state.silent_streak,
    }


def restore_telemetry(payload: dict | None) -> CrashTelemetryState:
    """Rehydrate state from a payload dict (e.g., pulled from traderData)."""
    state = CrashTelemetryState()
    if not isinstance(payload, dict):
        return state
    errors = payload.get("recent_errors", [])
    if isinstance(errors, list):
        for item in errors:
            if isinstance(item, (list, tuple)) and len(item) == 4:
                state.recent_errors.append(tuple(item))  # type: ignore[arg-type]
    state.cooloff_remaining = int(payload.get("cooloff_remaining", 0))
    state.last_successful_tick = int(payload.get("last_successful_tick", -1))
    state.silent_streak = int(payload.get("silent_streak", 0))
    return state

# ========================================================================
# src/core/primitives/portfolio_context.py
# ========================================================================

"""Cross-product portfolio context (fixes D3 in R3+ architecture).

Existing ``StrategyContext`` carries only one product's snapshot. A
basket-arb strategy fundamentally needs to read multiple products'
snapshots at once (basket + constituents). Rather than fork
``StrategyContext``, this module provides a ``PortfolioSnapshot`` that
sits alongside the single-product snapshot. The trader dispatch layer
builds it once per tick and passes it to strategies that opt in.

Existing single-product strategies ignore the new field (they never
read it), so this is a non-breaking extension.

Access patterns:

    # Single-product strategy (unchanged)
    def generate_intent(self, context: StrategyContext):
        snap = context.snapshot
        ...

    # Cross-product strategy (new)
    def generate_intent(self, context: StrategyContext):
        portfolio = context.portfolio  # PortfolioSnapshot | None
        if portfolio is None:
            # Degrade gracefully — portfolio not populated
            return self._single_product_fallback(context)
        basket_snap = portfolio.for_product("BASKET")
        coc_snap   = portfolio.for_product("COCOA")
        ...

The old-school single-product StrategyContext still works; R3+ engines
build on this extension.
"""






@dataclass(frozen=True)
class PortfolioSnapshot:
    """Read-only view of all products' books at one tick.

    Built by the trader dispatch layer from the full ``TradingState`` and
    shared across all strategies for the tick. Also carries cross-product
    signal values and counterparty state that were materialized before
    per-product strategy dispatch (so single-product strategies can still
    opt in to these signals without re-computing).
    """

    timestamp: Timestamp
    snapshots: Mapping[Product, NormalizedSnapshot] = field(
        default_factory=lambda: MappingProxyType({})
    )

    # Cross-product positions: same as per-product snapshots' .position, but
    # exposed at the portfolio level for convenience and for strategies that
    # aggregate positions (e.g., an options book that tracks aggregate delta).
    positions: Mapping[Product, int] = field(
        default_factory=lambda: MappingProxyType({})
    )

    # Per-product position limits. Trader-provided so strategies don't have
    # to re-fetch from config.
    position_limits: Mapping[Product, int] = field(
        default_factory=lambda: MappingProxyType({})
    )

    # Cross-exchange conversion data — best-bid / best-ask on the remote
    # exchange per product, extracted from TradingState.observations by
    # the Trader. Populated only for products that have a
    # ConversionObservation this tick; absent otherwise.
    remote_quotes: Mapping[Product, "RemoteQuote"] = field(
        default_factory=lambda: MappingProxyType({})
    )

    def for_product(self, product: Product) -> NormalizedSnapshot | None:
        """Return the snapshot for a product, or None if absent this tick."""
        return self.snapshots.get(product)

    def position_of(self, product: Product) -> int:
        return int(self.positions.get(product, 0))

    def limit_of(self, product: Product) -> int:
        return int(self.position_limits.get(product, 0))

    def remote_for(self, product: Product) -> "RemoteQuote | None":
        return self.remote_quotes.get(product)

    def products(self) -> tuple[Product, ...]:
        return tuple(self.snapshots.keys())


def build_portfolio_snapshot(
    timestamp: Timestamp,
    snapshots: Mapping[Product, NormalizedSnapshot],
    position_limits: Mapping[Product, int],
    remote_quotes: "Mapping[Product, RemoteQuote] | None" = None,
) -> PortfolioSnapshot:
    """Factory used by the trader dispatch layer.

    Extracts positions from each snapshot (since ``NormalizedSnapshot``
    already carries ``.position``) and freezes the maps.
    """
    positions = {p: int(s.position) for p, s in snapshots.items()}
    return PortfolioSnapshot(
        timestamp=timestamp,
        snapshots=MappingProxyType(dict(snapshots)),
        positions=MappingProxyType(positions),
        position_limits=MappingProxyType(dict(position_limits)),
        remote_quotes=MappingProxyType(dict(remote_quotes or {})),
    )

# ========================================================================
# src/core/primitives/portfolio_risk.py
# ========================================================================

"""Portfolio-level risk manager (fixes D3 + D5 at the risk layer).

Extends the existing per-product RiskManager to coordinate limits
across products. Needed when:

- Basket arb: basket position + constituent positions share capacity
  across a logical "arb book". Need aggregate exposure tracking.
- Options MM: per-strike positions aggregate to a net delta that must
  be hedged at the underlying. Aggregate delta limit applies.
- Stat-arb pairs: position in product A implies position in product B
  via hedge ratio; need joint capacity management.

This module wraps the existing RiskManager (unchanged) and adds a
cross-product coordinator on top. Per-product clipping still happens;
we just also surface cross-product aggregate metrics and allow
arb-tagged strategies to reserve capacity.

Also: residual allocator default=on for arb-tagged strategies (D5).
"""




StrategyTag = Literal["mm", "arb", "directional", "hedger"]


@dataclass(frozen=True)
class ProductTag:
    """Metadata on how a product is being traded this tick."""

    product: str
    strategy_tag: StrategyTag = "mm"
    """How this product is being used: MM (symmetric quotes), ARB (hedge
    leg of a spread), DIRECTIONAL (signal-driven take), HEDGER (delta
    neutralizer for an options book)."""

    # For arb legs: the logical "group" this product belongs to. Used to
    # track aggregate exposure of a basket-arb or options-book setup.
    arb_group: str | None = None

    # For hedger legs: the target product whose risk this leg hedges.
    hedges_product: str | None = None


@dataclass(frozen=True)
class PortfolioCapacity:
    """Cross-product capacity summary for one tick."""

    per_product: Mapping[str, Capacity]
    gross_exposure: int
    """Sum of |position| across all products."""

    net_exposure_by_group: Mapping[str, int]
    """Signed net exposure per arb_group (baskets / options books)."""


@dataclass(frozen=True)
class PortfolioRiskConfig:
    """Portfolio-level risk gates."""

    # Caps on gross exposure (sum of |positions|). 0 = no cap.
    max_gross_exposure: int = 0

    # Per-arb-group caps on net exposure (signed sum of positions in the group).
    max_net_exposure_per_group: int = 0

    # If True, residual-allocator defaults ON for arb-tagged strategies
    # (fixes D5).
    residual_default_on_for_arb: bool = True


class PortfolioRiskManager:
    """Composes cross-product checks on top of per-product clipping.

    Usage:

        mgr = PortfolioRiskManager(base=RiskManager(), config=...)
        # Per-product clipping (unchanged from existing RiskManager)
        clipped = mgr.clip_orders(product, orders, position, limit)
        # Cross-product capacity (new)
        cap = mgr.portfolio_capacity(positions, limits, tags)
        # Group-level exposure (new)
        exposure = mgr.group_exposure("basket1_arb", positions, tags)
    """

    def __init__(
        self,
        *,
        base: RiskManager | None = None,
        config: PortfolioRiskConfig | None = None,
    ) -> None:
        self.base = base or RiskManager()
        self.config = config or PortfolioRiskConfig()

    # ---------------- per-product (delegated to base)

    def clip_orders(
        self,
        product: str,
        orders: list[Order],
        current_position: int,
        limit: int,
    ) -> list[Order]:
        return self.base.clip_orders(product, orders, current_position, limit)

    def capacity(self, position: int, limit: int) -> Capacity:
        return self.base.capacity(position, limit)

    # ---------------- cross-product (new)

    def portfolio_capacity(
        self,
        positions: Mapping[str, int],
        limits: Mapping[str, int],
        tags: Mapping[str, ProductTag] | None = None,
    ) -> PortfolioCapacity:
        per_product = {
            p: self.base.capacity(positions.get(p, 0), limits.get(p, 0))
            for p in set(positions) | set(limits)
        }
        gross = sum(abs(positions.get(p, 0)) for p in positions)
        net_by_group: dict[str, int] = {}
        if tags is not None:
            for product, tag in tags.items():
                if tag.arb_group is None:
                    continue
                net_by_group[tag.arb_group] = (
                    net_by_group.get(tag.arb_group, 0) + positions.get(product, 0)
                )
        return PortfolioCapacity(
            per_product=per_product,
            gross_exposure=gross,
            net_exposure_by_group=net_by_group,
        )

    def group_exposure(
        self,
        arb_group: str,
        positions: Mapping[str, int],
        tags: Mapping[str, ProductTag],
    ) -> int:
        return sum(
            positions.get(product, 0)
            for product, tag in tags.items()
            if tag.arb_group == arb_group
        )

    def residual_allowed(self, tag: ProductTag) -> bool:
        """Does the residual allocator run for this strategy?

        Replaces the global ``ResidualConfig.enabled=False`` default with
        a tag-aware decision. Arb strategies have slack by design; MM
        strategies already saturate the book.
        """
        if tag.strategy_tag == "arb" and self.config.residual_default_on_for_arb:
            return True
        if tag.strategy_tag == "directional":
            # Directional strategies take discrete positions; residual
            # would dilute the signal. Default off.
            return False
        if tag.strategy_tag == "hedger":
            # Hedgers fire only to neutralize delta. No residual.
            return False
        # MM default: off (their primary logic already uses full capacity).
        return False

    def exceeds_gross_cap(self, gross: int) -> bool:
        return self.config.max_gross_exposure > 0 and gross > self.config.max_gross_exposure

    def exceeds_group_cap(self, group_net: int) -> bool:
        cap = self.config.max_net_exposure_per_group
        return cap > 0 and abs(group_net) > cap

# ========================================================================
# src/core/primitives/signal_bus.py
# ========================================================================

"""SignalBus — first-class pub/sub for trading signals (fixes D4).

Before this primitive, FlowAnalyzer was observational-only (its own
docstring: "never alters strategy behaviour"). Signals had no way to
influence decisions. This module introduces a pub/sub bus where:

- **Emitters** (flow analyzer, basket-spread calculator, IV-residual
  computer, counterparty-state model, lead-lag predictor) publish
  signal values per tick.

- **Consumers** (strategies, fair-value estimators, sizers, hedgers)
  subscribe to signals and read their current value.

- **Every signal carries validation metadata** (rolling IC, shuffle
  baseline, sample count, last-validated tick). No untrusted signal
  reaches a consumer without passing validation (fixes D9).

- **Snapshot is per-tick** — the bus is rebuilt each tick from the
  latest emitter outputs. There is no cross-tick pub/sub state; all
  that lives on the emitter/consumer side. Keeps the bus dumb.

Usage:

    bus = SignalBus()
    bus.emit(SignalValue(name="basket_spread_z", value=2.4,
        validated=True, ic=0.18, metadata={"window": 500}))
    val = bus.get("basket_spread_z")
    if val and val.validated and abs(val.ic) > 0.03:
        # act on the signal
"""




@dataclass(frozen=True)
class SignalValue:
    """One signal reading at one tick.

    Immutable so consumers can't mutate emitter state.
    """

    name: str
    """Unique signal identifier (e.g., 'basket_b1_spread_z', 'ash_obi')."""

    value: float
    """The numeric signal value at this tick."""

    validated: bool = False
    """True iff the signal has passed its validation harness.
    Unvalidated signals can be emitted (for logging/research) but
    consumers should ignore them for trading decisions."""

    ic: float | None = None
    """Rolling information coefficient (Pearson correlation with forward
    returns). None if not yet measured."""

    sample_count: int = 0
    """Number of ticks contributing to the rolling IC estimate."""

    last_validated_tick: int = -1
    """Most recent tick at which full validation was run."""

    metadata: Mapping[str, float | int | str | bool] = field(
        default_factory=lambda: MappingProxyType({})
    )
    """Extra context (window size, regime flag, etc.)."""


class SignalBus:
    """Per-tick signal registry. Rebuilt each tick by the trader layer.

    Design decisions:
    - No cross-tick state on the bus itself. Emitters hold their own
      rolling history; the bus just mirrors the current-tick snapshot.
    - Last emit wins (no multi-value per name). Emitters can subscribe
      to each other if they want to chain.
    - Name-space is flat; use prefixes ('basket.b1.spread_z',
      'options.10000.iv_residual') for organization.
    - Consumers may ask for ``trusted_only=True`` to filter out any
      value whose ``validated`` is False. This is the enforcement
      point for D9.
    """

    def __init__(self) -> None:
        self._values: dict[str, SignalValue] = {}

    def emit(self, value: SignalValue) -> None:
        """Publish a signal value for the current tick."""
        self._values[value.name] = value

    def get(self, name: str, *, trusted_only: bool = True) -> SignalValue | None:
        """Return the current-tick value, or None.

        ``trusted_only=True`` (default) filters out un-validated signals;
        pass ``trusted_only=False`` to access research signals.
        """
        v = self._values.get(name)
        if v is None:
            return None
        if trusted_only and not v.validated:
            return None
        return v

    def all(self, *, trusted_only: bool = True) -> Mapping[str, SignalValue]:
        """Current-tick snapshot of all signals."""
        if trusted_only:
            return MappingProxyType(
                {name: v for name, v in self._values.items() if v.validated}
            )
        return MappingProxyType(dict(self._values))

    def names(self) -> tuple[str, ...]:
        return tuple(self._values.keys())

    def clear(self) -> None:
        """Drop all values. Called at tick start by the trader layer."""
        self._values.clear()


def empty_signal_bus() -> SignalBus:
    """Factory for a fresh bus (used by test harnesses and initial state)."""
    return SignalBus()

# ========================================================================
# src/core/primitives/engine_orchestrator.py
# ========================================================================

"""EngineOrchestrator — coordinates cross-product engines.

Design principles:

- **One orchestrator per Trader.** Owns a SignalBus, a CrashTelemetryState,
  and a reference to PortfolioRiskManager shared with per-product strategies.

- **Engines are plugins.** The orchestrator doesn't know about baskets or
  options specifically. Any object that implements the ``PersistableEngine``
  protocol can be registered.

- **Product ownership is explicit.** Each engine declares which products it
  owns via ``owned_products``. The orchestrator surfaces an aggregate set
  so the Trader can skip per-product dispatch for owned products (preventing
  conflicting orders).

- **State persistence is first-class.** ``to_state()`` / ``from_state()``
  round-trip through ``EngineState.engines[engine_id]``. The orchestrator
  handles save/restore; engines own their own serialization shape.

- **Crash-safe dispatch.** Every ``engine.step()`` call is wrapped in
  ``run_with_telemetry``. A single engine crash does not take down the
  entire tick.
"""





@runtime_checkable
class PersistableEngine(Protocol):
    """Contract every orchestrated engine must satisfy."""

    @property
    def engine_id(self) -> str:
        """Stable identifier used for state persistence keying."""
        ...

    @property
    def owned_products(self) -> frozenset[str]:
        """Products this engine emits orders for (inclusive of any hedge legs).

        Per-product dispatch is skipped for owned products to prevent
        conflicting orders. An empty set is valid (engine reads state but
        emits no orders this tick — e.g., CounterpartyIntel in pure
        observation mode).
        """
        ...

    def step(
        self, portfolio: PortfolioSnapshot, *, current_tick: int,
    ) -> "EngineStepResult":
        """Emit orders + conversions + tags for this tick."""
        ...

    def to_state(self) -> dict:
        """JSON-serializable snapshot for traderData persistence."""
        ...

    def from_state(self, blob: dict) -> None:
        """Restore from a previously-saved blob. Missing keys → defaults."""
        ...


@dataclass(frozen=True)
class EngineStepResult:
    """Unified return type for every engine step.

    Empty defaults let engines omit what they don't produce (e.g., a pure
    MM engine has conversions=0; a stat-arb engine has conversions != 0;
    a counterparty intelligence engine has orders=[]).
    """

    orders: list[Order] = field(default_factory=list)
    conversions: int = 0
    tags: dict[str, ProductTag] = field(default_factory=dict)


@dataclass
class OrchestratorStepSummary:
    """Aggregate output from one orchestrator tick.

    The Trader consumes ``orders_by_product`` + ``total_conversions`` and
    skips per-product dispatch for products in ``handled_products``.
    """

    orders_by_product: dict[str, list[Order]] = field(
        default_factory=lambda: defaultdict(list)
    )
    total_conversions: int = 0
    tags: dict[str, ProductTag] = field(default_factory=dict)
    handled_products: set[str] = field(default_factory=set)
    errored_engines: list[str] = field(default_factory=list)


class EngineOrchestrator:
    """Central dispatcher for cross-product engines.

    Lifecycle per Trader tick:
    1. ``restore(engine_state)`` — load saved state once at Trader init OR
       every tick (Trader.run() is re-entrant in the Prosperity container).
    2. ``step(portfolio, current_tick=...)`` — runs each engine, aggregates
       results.
    3. ``persist(engine_state)`` — writes fresh state back before
       StateStore.save().
    """

    def __init__(
        self,
        engines: list[PersistableEngine] | None = None,
        *,
        risk: PortfolioRiskManager | None = None,
        crash_config: CrashTelemetryConfig | None = None,
        signal_bus: SignalBus | None = None,
    ) -> None:
        self._engines: list[PersistableEngine] = list(engines or [])
        # Canonical wiring: every engine that wants its emits to reach
        # other engines MUST share this bus. Construct the bus first,
        # pass it to ``signal_bus`` here AND to each engine's ``bus=``
        # constructor argument. If ``signal_bus`` is None, we create a
        # fresh bus — callers who did not share one explicitly can reach
        # it via ``orchestrator.signal_bus`` and pass it to subsequent
        # components.
        self.signal_bus = signal_bus or SignalBus()
        self.risk = risk or PortfolioRiskManager()
        self._crash_config = crash_config or CrashTelemetryConfig()
        self._telemetry = CrashTelemetryState()
        self._validate_engine_ids()

    def _validate_engine_ids(self) -> None:
        seen: set[str] = set()
        for engine in self._engines:
            eid = engine.engine_id
            if not eid:
                raise ValueError(
                    f"Engine {type(engine).__name__} has empty engine_id; "
                    f"state persistence will collide."
                )
            if eid in seen:
                raise ValueError(
                    f"Duplicate engine_id {eid!r}; engine_id must be unique."
                )
            seen.add(eid)

    # ========================================================= lifecycle

    def restore(self, engine_state: EngineState) -> None:
        """Pull per-engine state blobs + crash telemetry from EngineState."""
        for engine in self._engines:
            blob = engine_state.engines.get(engine.engine_id, {})
            if isinstance(blob, dict):
                engine.from_state(blob)
        telemetry_blob = engine_state.engines.get("__telemetry__", {})
        if isinstance(telemetry_blob, dict) and telemetry_blob:
            self._telemetry = restore_telemetry(telemetry_blob)

    def persist(self, engine_state: EngineState) -> None:
        """Push per-engine state back into EngineState for StateStore.save()."""
        for engine in self._engines:
            try:
                blob = engine.to_state()
            except Exception:  # noqa: BLE001 — a bad to_state must not halt the tick
                blob = {}
            if not isinstance(blob, dict):
                blob = {}
            engine_state.set_engine_state(engine.engine_id, blob)
        engine_state.set_engine_state(
            "__telemetry__", snapshot_telemetry(self._telemetry),
        )

    # ========================================================= step

    def step(
        self, portfolio: PortfolioSnapshot, *, current_tick: int,
    ) -> OrchestratorStepSummary:
        """Run every engine, aggregate their orders + conversions + tags."""
        summary = OrchestratorStepSummary()
        # Clear signal bus at tick start. Emitters republish each tick;
        # consumers see a fresh view.
        self.signal_bus.clear()

        if self._telemetry.is_halted():
            # Global kill-switch active: engines are all halted until cooloff.
            self._telemetry.tick_cooloff()
            return summary

        for engine in self._engines:
            for product in engine.owned_products:
                summary.handled_products.add(product)

        for engine in self._engines:
            result, raised = run_with_telemetry(
                lambda e=engine: e.step(portfolio, current_tick=current_tick),
                tick=current_tick,
                product=engine.engine_id,
                state=self._telemetry,
                config=self._crash_config,
                default=EngineStepResult(),
            )
            if raised:
                summary.errored_engines.append(engine.engine_id)
                continue
            for order in result.orders:
                summary.orders_by_product[order.symbol].append(order)
            summary.total_conversions += result.conversions
            summary.tags.update(result.tags)

        return summary

    # ========================================================= introspection

    @property
    def engine_count(self) -> int:
        return len(self._engines)

    @property
    def telemetry(self) -> CrashTelemetryState:
        return self._telemetry

    def engine_ids(self) -> tuple[str, ...]:
        return tuple(e.engine_id for e in self._engines)

