# ========================================================================
# src/conversions/layer.py
# ========================================================================

"""Cross-exchange conversion layer (fixes D7 for stat-arb products).

Handles IMC Prosperity-style cross-exchange arbitrage (P2 Orchids, P3
Macarons). The core abstraction: a local tradable book + a remote
"conversion" exchange with its own best-bid / best-ask, import / export
tariffs, transport cost, per-unit storage cost.

The arb is a two-legged lock:

    sell locally at price P_L if:  P_L > conversion_ask + import_tariff + transport

    buy locally at price P_L if:   P_L < conversion_bid - export_tariff - transport

and then convert the position at the remote exchange.

Key findings from R1/R2 and P3 top-team archaeology:

- **Signed break-even** handles negative tariffs (subsidies) — the
  Macaron edge.
- **Batched conversions (3× cap)** handle the per-tick conversion
  limit: stockpile during high-fill windows so conversions can happen
  continuously even when the bot is absent. Both P3 top-2 teams missed
  this and left ~2× P&L on the table (transcript-1).
- **External signal = regime flag**, not linear regressor. Percentile
  over rolling window: <25th = squeeze (buy-and-hold), >75th = glut
  (sell aggressively), middle = normal arb.
- **Fill-rate probe**: for hidden-taker bots, the fill probability
  depends on the exact price-offset to mid. Thompson bandit
  auto-calibrates the best offset.

Pure-function building blocks plus one stateful ``ConversionLayer``
that tracks inventory across ticks (for stockpile batching).
"""



TariffSide = Literal["import", "export"]


@dataclass(frozen=True)
class ConversionSpec:
    """Static tariff / transport parameters for one cross-exchange product."""

    transport_fee: float = 0.0
    """Per-unit transport cost, applied on every conversion (both directions)."""

    import_tariff: float = 0.0
    """Added to cost when buying remote + importing. NEGATIVE = subsidy."""

    export_tariff: float = 0.0
    """Added to cost when selling locally + exporting. NEGATIVE = subsidy."""

    storage_cost: float = 0.0
    """Per-unit-per-tick cost of holding inventory (long or short)."""

    conv_cap_per_tick: int = 10
    """Maximum units that can be converted per tick (IMC limit)."""

    def __post_init__(self) -> None:
        if self.conv_cap_per_tick <= 0:
            raise ValueError("conv_cap_per_tick must be > 0")
        if self.storage_cost < 0:
            raise ValueError("storage_cost must be >= 0")


@dataclass(frozen=True)
class RemoteQuote:
    """Best-bid / best-ask on the conversion exchange, per tick."""

    bid: float
    """Remote bid — we sell INTO this (import direction: ours → remote)."""

    ask: float
    """Remote ask — we buy FROM this (export direction: remote → ours).

    Naming follows "what does it cost US" convention. Some IMC docs use
    the opposite sign; this module keeps the convention explicit.
    """


# ============================================================= break-even


def sell_local_break_even(spec: ConversionSpec, remote: RemoteQuote) -> float:
    """Minimum LOCAL BID we'd need in order to profitably sell local + buy remote.

    We want: local_bid_price  >  sell_local_break_even.
    If the condition holds, we sell locally and immediately buy remote
    to flatten, locking in the difference.
    """
    # We sell locally at price P_L, then buy remote at remote.ask,
    # paying transport + import_tariff. Profit per unit = P_L - remote.ask - transport - import_tariff.
    # Break-even when profit = 0 ⇒ P_L = remote.ask + transport + import_tariff.
    return remote.ask + spec.transport_fee + spec.import_tariff


def buy_local_break_even(spec: ConversionSpec, remote: RemoteQuote) -> float:
    """Maximum LOCAL ASK at which we'd profitably buy local + sell remote.

    We want: local_ask_price  <  buy_local_break_even.
    """
    return remote.bid - spec.transport_fee - spec.export_tariff


def arb_edge(
    *,
    local_bid: float | None,
    local_ask: float | None,
    spec: ConversionSpec,
    remote: RemoteQuote,
) -> float:
    """Per-unit arb edge at current books. Positive = arb available.

    Picks the direction (sell-local or buy-local) that produces edge,
    or 0 if neither holds.
    """
    best_edge = 0.0
    if local_bid is not None:
        be = sell_local_break_even(spec, remote)
        best_edge = max(best_edge, local_bid - be)
    if local_ask is not None:
        be = buy_local_break_even(spec, remote)
        best_edge = max(best_edge, be - local_ask)
    return best_edge


# ============================================================= stockpile


@dataclass(frozen=True)
class StockpileConfig:
    """Batched-execution parameters.

    Transcript-1: optimal batch = ~3× conv_cap_per_tick. Smaller leaves
    P&L on the table (can't convert when bot absent); larger accumulates
    excess storage cost.
    """

    batch_multiplier: float = 3.0
    """Target batch size = batch_multiplier × conv_cap_per_tick."""

    max_inventory_buffer: int | None = None
    """Hard cap on stockpile size. None = use position limit."""


def target_batch_size(
    spec: ConversionSpec,
    config: StockpileConfig,
    arb_edge_per_unit: float,
    current_inventory: int,
) -> int:
    """How many units to trade LOCALLY this tick if arb is open.

    Returns a non-negative size. Zero when no arb edge or at inventory cap.
    Positive = do the local leg (remote conversion happens next tick).
    """
    if arb_edge_per_unit <= 0:
        return 0
    target = int(math.floor(config.batch_multiplier * spec.conv_cap_per_tick))
    # Don't exceed the buffer cap (if any).
    if config.max_inventory_buffer is not None:
        room = max(0, config.max_inventory_buffer - abs(current_inventory))
        target = min(target, room)
    return target


def conversion_size(
    spec: ConversionSpec,
    inventory: int,
) -> int:
    """Number of units to convert this tick.

    Positive = buy remote (net-short locally becomes flat).
    Negative = sell remote (net-long locally becomes flat).
    Capped at conv_cap_per_tick.
    """
    sign = -1 if inventory > 0 else (1 if inventory < 0 else 0)
    if sign == 0:
        return 0
    amount = min(abs(inventory), spec.conv_cap_per_tick)
    return sign * amount


# ============================================================= regime flag


@dataclass
class RegimeDetector:
    """Percentile-based regime flag on an external signal (sunlight etc).

    Fixes F4 hidden-alpha finding: treat external signals as DISCRETE
    regime flags, NOT linear regressors. A 99% R² linear fit is a
    lookahead-leakage tell.
    """

    lookback_window: int = 100
    """Rolling window for percentile calculation."""

    squeeze_percentile: float = 0.25
    """Below this → 'squeeze' regime (accumulate inventory)."""

    glut_percentile: float = 0.75
    """Above this → 'glut' regime (offload)."""

    # Bounded deque: O(1) append + automatic eviction. Previously a plain
    # list with ``pop(0)`` which is O(n) per observation — the per-tick
    # cost was small but scaled quadratically with lookback_window.
    _history: deque[float] = field(init=False)

    def __post_init__(self) -> None:
        object.__setattr__(self, "_history", deque(maxlen=self.lookback_window))

    def observe(self, value: float) -> None:
        self._history.append(value)

    def regime(self, current_value: float) -> Literal["squeeze", "normal", "glut"]:
        if len(self._history) < 10:
            return "normal"
        sorted_hist = sorted(self._history)
        n = len(sorted_hist)
        lo_idx = int(self.squeeze_percentile * n)
        hi_idx = int(self.glut_percentile * n)
        lo_val = sorted_hist[lo_idx]
        hi_val = sorted_hist[hi_idx]
        if current_value <= lo_val:
            return "squeeze"
        if current_value >= hi_val:
            return "glut"
        return "normal"


# ============================================================= fill probe


@dataclass
class FillRateProbe:
    """Thompson-bandit probe for hidden-taker fill price.

    P3 macaron finding: placing sell at `int(external_bid + 0.5)` got
    filled ~60%. The exact price-offset to mid matters more than the
    direction. This probe iteratively adjusts the offset and tracks
    fill success rate per offset, converging on the optimum.

    Simpler than full Thompson sampling — uses a success/trial count
    per offset and picks the offset with the highest Laplace-smoothed
    success rate (eps-greedy with eps=0.1 for exploration).
    """

    min_offset: int = -3
    max_offset: int = 3
    exploration_epsilon: float = 0.1
    _trials: dict[int, int] = field(default_factory=dict)
    _successes: dict[int, int] = field(default_factory=dict)

    def _rate(self, offset: int) -> float:
        s = self._successes.get(offset, 0)
        t = self._trials.get(offset, 0)
        # Laplace smoothing.
        return (s + 1) / (t + 2)

    def pick_offset(self, seed_rng: "random.Random | None" = None) -> int:
        import random as _r

        rng = seed_rng or _r.Random()
        if rng.random() < self.exploration_epsilon:
            return rng.randint(self.min_offset, self.max_offset)
        offsets = list(range(self.min_offset, self.max_offset + 1))
        return max(offsets, key=self._rate)

    def record(self, offset: int, *, filled: bool) -> None:
        self._trials[offset] = self._trials.get(offset, 0) + 1
        if filled:
            self._successes[offset] = self._successes.get(offset, 0) + 1

    def best_offset(self) -> int:
        offsets = list(range(self.min_offset, self.max_offset + 1))
        return max(offsets, key=self._rate)

# ========================================================================
# src/conversions/adapter.py
# ========================================================================

"""Adapter: ``TradingState.observations.conversionObservations`` → ``RemoteQuote``.

The Prosperity container exposes cross-exchange quotes via
``TradingState.observations.conversionObservations[product]`` as a
``ConversionObservation`` carrying:

    bidPrice, askPrice, transportFees, exportTariff, importTariff,
    sunlight, humidity

The engines work in terms of ``RemoteQuote(bid, ask)`` (a minimal view)
plus tariff/transport fees carried on ``ConversionSpec`` (tariffs vary
per tick in IMC scenarios). This adapter:

1. Extracts a ``RemoteQuote`` per product.
2. Extracts per-product tariff overrides so ``StatArbEngine`` sees the
   current tick's actual numbers (not a frozen config snapshot).
3. Extracts the raw external signal (sunlight / humidity / sugarPrice)
   for downstream ``SignalBus`` emission.

Design notes:

- **Pure functions.** No stored state — the adapter is called on every
  tick from ``Trader.run``.
- **Empty-input safe.** Products with no conversion observation are
  simply absent from the returned mapping (downstream engines check
  ``portfolio.remote_for(p) is None``).
- **Non-breaking.** If ``observations`` is None or has no
  ``conversionObservations`` attribute, returns empty mappings. This
  lets unit tests pass a bare ``TradingState`` without observations.
"""





@dataclass(frozen=True)
class ConversionTick:
    """Per-product tick-level conversion data extracted from observations.

    The engine pulls ``remote`` for the arb edge, ``tariff_overrides`` to
    clone its ``ConversionSpec`` with current values, and ``signals`` for
    regime detection.
    """

    remote: RemoteQuote
    tariff_overrides: ConversionSpec
    signals: dict[str, float]


def extract_conversion_ticks(
    state: TradingState,
    *,
    base_specs: Mapping[str, ConversionSpec] | None = None,
) -> dict[str, ConversionTick]:
    """Build per-product ``ConversionTick`` from the raw TradingState.

    ``base_specs`` provides the default ``ConversionSpec`` per product
    (mainly for ``conv_cap_per_tick`` + ``storage_cost`` which are NOT
    in the observation — they're static competition parameters). The
    adapter overrides ``transport_fee``, ``import_tariff``,
    ``export_tariff`` from the current tick's observation.

    Returns empty dict if observations are absent.
    """
    observations = getattr(state, "observations", None)
    if observations is None:
        return {}
    conv_map = getattr(observations, "conversionObservations", None)
    if not conv_map:
        return {}

    out: dict[str, ConversionTick] = {}
    for product, obs in conv_map.items():
        if not isinstance(obs, ConversionObservation):
            # Defensive: external code may mis-populate observations.
            continue
        base = (base_specs or {}).get(product) or ConversionSpec()
        try:
            remote = RemoteQuote(bid=float(obs.bidPrice), ask=float(obs.askPrice))
        except (TypeError, ValueError):
            continue
        try:
            tariff_overrides = ConversionSpec(
                transport_fee=float(obs.transportFees),
                import_tariff=float(obs.importTariff),
                export_tariff=float(obs.exportTariff),
                storage_cost=base.storage_cost,
                conv_cap_per_tick=base.conv_cap_per_tick,
            )
        except (TypeError, ValueError):
            # Malformed observation: fall back to the static base spec.
            tariff_overrides = base

        # Raw external signals — the engine decides which to consume via
        # its config.external_signal_name. Both sunlight & humidity are
        # published in case multiple engines consume them.
        signals: dict[str, float] = {}
        for attr in ("sunlight", "humidity"):
            val = getattr(obs, attr, None)
            if val is None:
                continue
            try:
                signals[attr] = float(val)
            except (TypeError, ValueError):
                continue

        out[product] = ConversionTick(
            remote=remote,
            tariff_overrides=tariff_overrides,
            signals=signals,
        )
    return out


def extract_remote_quotes(state: TradingState) -> dict[str, RemoteQuote]:
    """Convenience: just the ``RemoteQuote`` map.

    Callers who don't need tariff overrides or signals use this. The
    ``PortfolioSnapshot`` ``remote_quotes`` field is populated from here.
    """
    return {p: t.remote for p, t in extract_conversion_ticks(state).items()}

# ========================================================================
# src/trader.py
# ========================================================================

"""Entrypoint for the Prosperity live trading container.

Responsibilities of this file are deliberately narrow:

1. Restore persistent state from ``state.traderData``.
2. Normalize the incoming ``TradingState`` into canonical snapshots.
3. Dispatch each known product to its configured strategy via the
   ``STRATEGY_REGISTRY`` in ``src/strategies/``.
4. Route the strategy's intent through execution and risk layers.
5. Update rolling per-product memory.
6. Serialize next-iteration state back into ``traderData``.
7. Return ``(orders, conversions, traderData)``.

This file never contains product-specific pricing or execution
heuristics. Those live in ``strategies/`` and ``core/``.

Safety: ``run()`` is wrapped in a top-level safety net. If any
downstream module raises, the trader returns an empty orders dict and
preserves the previous ``traderData`` so the Prosperity container does
not crash. Tests can set ``_reraise_exceptions=True`` to opt out and
surface errors.
"""




# Lazy-import gate. The following modules are heavy and only needed for
# per-product strategy dispatch. An R3 submission whose every product is
# owned by an orchestrator engine never touches them, and the R3
# submission bundle drops them entirely. TYPE_CHECKING keeps the type
# annotations below honest without pulling runtime imports.

_LOG = logging.getLogger(__name__)

# Memory key used by the day-rollover detector to remember the last
# snapshot.timestamp we saw for a product. A new snapshot whose
# timestamp is *less than* this value indicates the simulator has
# rolled over to a new day (timestamps reset to 0 on each new day).
_LAST_SEEN_TIMESTAMP_KEY = "last_seen_timestamp"


class Trader:
    def __init__(
        self,
        config: EngineConfig | None = None,
        *,
        state_store: StateStore | None = None,
        reraise_exceptions: bool = False,
        orchestrator: "EngineOrchestrator | None" = None,
    ) -> None:
        # Function-scope import: the bundler strips all src-package
        # import lines from both module scope and function bodies, and
        # the completeness check ignores function-scope src imports
        # (see ``strip_module`` + ``_collect_src_imports`` in
        # export_submission.py). At runtime the bundled flat namespace
        # resolves ``default_engine_config`` to:
        #   - R2 bundles: the multi-product factory in config.py.
        #   - R3 bundles: the stub in config_core.py (config.py is
        #     dropped from the bundle; the stub raises with a clear
        #     message directing callers to supply their own EngineConfig).
        if config is None:
            config = default_engine_config()
        self.config = config
        self.state_store = state_store or StateStore(
            version=self.config.state_version,
            max_chars=self.config.max_trader_data_chars,
        )
        self.market_data = MarketDataAdapter()
        self.signal_engine = SignalEngine()
        self.execution_engine = ExecutionEngine()
        self.risk_manager = RiskManager()
        self.residual_allocator = ResidualAllocator(self.config.residual_config)
        self.flow_analyzer = FlowAnalyzer(self.config.scanner_config)
        self.logger = DecisionLogger()
        self._reraise_exceptions = reraise_exceptions
        # Cross-product engine orchestrator (R3+). Optional: legacy R1/R2
        # runs pass None and behave exactly as before (no portfolio snapshot,
        # no engine dispatch, conversions fixed at 0).
        self.orchestrator = orchestrator
        # FairValueEngine + strategies are only instantiated when there
        # is at least one product configured with a strategy_name. R3
        # submissions that rely entirely on orchestrator-owned products
        # leave ``products={}`` and skip the (heavy) fair_value + strategy
        # machinery entirely — keeps the R3 bundle slim.
        self.fair_value_engine: "FairValueEngine | None" = None
        self.strategies: dict[str, "BaseStrategy"] = self._build_strategies()

    # ---------------------------------------------------------- setup

    def _build_strategies(self) -> dict[str, "BaseStrategy"]:
        strategies: dict[str, BaseStrategy] = {}
        if not self.config.products:
            # Pure-orchestrator submission: no per-product strategies,
            # so skip the FairValueEngine / strategy-registry imports
            # entirely. This is the hot path for R3 bundles that drop
            # fair_value.py and strategies/* from the submission.
            return strategies

        # Lazy import: the fair_value + strategy subsystem is only
        # needed when at least one product has a strategy_name. Moving
        # these imports inside the function lets R3 bundles strip the
        # ~24 KB of fair_value + strategy modules when they are unused.

        self.fair_value_engine = FairValueEngine()
        for product_config in self.config.products.values():
            name = product_config.strategy_name
            if name in strategies:
                continue
            factory = STRATEGY_REGISTRY.get(name)
            if factory is None:
                _LOG.warning("Unknown strategy %r for product config; will be skipped", name)
                continue
            strategies[name] = factory(self.fair_value_engine, self.signal_engine)
        return strategies

    # ---------------------------------------------------------- contract

    # Round-2 Market Access Fee. The Prosperity container reads this
    # once at the start of the round; ignored in earlier rounds and in
    # local test runs. Value is sourced from EngineConfig.bid_value so
    # each export bundle ships with its own auction bid.
    def bid(self) -> int:
        return self.config.bid_value

    def run(self, state: TradingState) -> tuple[dict[str, list[Order]], int, str]:
        """Entry point called by the Prosperity container.

        Wraps ``_run_body`` in a top-level safety net. An unhandled
        exception in any sub-module would otherwise crash the container
        and lose the iteration entirely.
        """
        try:
            return self._run_body(state)
        except Exception:
            _LOG.exception("Trader.run crashed; returning empty orders")
            if self._reraise_exceptions:
                raise
            return {}, 0, state.traderData

    # ---------------------------------------------------------- body

    def _run_body(self, state: TradingState) -> tuple[dict[str, list[Order]], int, str]:
        engine_state = self.state_store.load(state.traderData)
        engine_state.version = self.config.state_version

        snapshots = self.market_data.normalize_state(state)
        results: dict[str, list[Order]] = {}

        # Build cross-product portfolio snapshot (includes remote quotes
        # extracted from ConversionObservations). Always constructed when
        # an orchestrator is present OR any strategy may introspect it via
        # StrategyContext.portfolio. Cheap — just shallow maps.
        # Orchestrator modules are imported lazily so R1/R2 bundles (which
        # don't ship primitives/conversions) never touch these symbols.
        portfolio = None
        orch_summary = None
        if self.orchestrator is not None:

            position_limits = {
                p: cfg.position_limit for p, cfg in self.config.products.items()
            }
            remote_quotes = extract_remote_quotes(state)
            portfolio = build_portfolio_snapshot(
                timestamp=state.timestamp,
                snapshots=snapshots,
                position_limits=position_limits,
                remote_quotes=remote_quotes,
            )
            # Restore engine state (idempotent across ticks — Prosperity
            # re-enters run() freshly each tick), then step all engines.
            self.orchestrator.restore(engine_state)
            orch_summary = self.orchestrator.step(
                portfolio, current_tick=state.timestamp,
            )
            # Orchestrator-owned products get their orders from engines,
            # not from per-product dispatch. Pre-seed results so the
            # returned dict shape still includes them.
            for product, orders in orch_summary.orders_by_product.items():
                results[product] = list(orders)

        handled_products = (
            orch_summary.handled_products if orch_summary else set()
        )

        for product, snapshot in snapshots.items():
            if product in handled_products:
                # An engine owns this product; skip per-product dispatch
                # to avoid conflicting orders. Engine orders are already
                # in ``results`` from the block above.
                continue

            product_config = self.config.product_config(product)
            if product_config is None:
                results[product] = []
                continue

            strategy = self.strategies.get(product_config.strategy_name)
            if strategy is None:
                results[product] = []
                continue

            memory = engine_state.for_product(product)
            self._maybe_flush_for_day_rollover(
                memory=memory,
                snapshot=snapshot,
                product_config=product_config,
            )
            legal_orders = self._step_product(
                product=product,
                snapshot=snapshot,
                memory=memory,
                product_config=product_config,
                strategy=strategy,
                timestamp=state.timestamp,
                portfolio=portfolio,
            )
            results[product] = legal_orders
            self._update_memory(memory, snapshot, product_config.history_length)
            memory.counters[_LAST_SEEN_TIMESTAMP_KEY] = int(snapshot.timestamp)

        # Persist engine state BEFORE state_store.save() so its budget-aware
        # truncation sees the full engine blobs.
        if self.orchestrator is not None:
            self.orchestrator.persist(engine_state)
            if orch_summary and orch_summary.errored_engines:
                _LOG.warning(
                    "Engines raised this tick: %s",
                    orch_summary.errored_engines,
                )

        trader_data = self.state_store.save(engine_state)
        conversions = orch_summary.total_conversions if orch_summary else 0

        # Per-tick summary: one structured event per run() that carries
        # the cross-cutting counters (orders per product, conversions,
        # errored engine count, handled-product set). Lets post-mortem
        # tooling reconstruct a round's engine behaviour from the log
        # without re-running the replay. Cheap — a single dict append.
        self._record_tick_summary(
            timestamp=state.timestamp,
            results=results,
            conversions=conversions,
            orch_summary=orch_summary,
        )

        return results, conversions, trader_data

    def _record_tick_summary(
        self,
        *,
        timestamp: int,
        results: dict[str, list[Order]],
        conversions: int,
        orch_summary,
    ) -> None:
        """Emit a compact per-tick summary into the DecisionLogger.

        Fields:
          - ``timestamp``: tick timestamp as received from Prosperity
          - ``order_counts``: ``{product: len(orders)}`` for products
            that emitted at least one order (empty products omitted to
            keep the event small)
          - ``conversions``: total conversions for this tick
          - ``engines``: number of engines run this tick (orchestrator
            mode only; 0 otherwise)
          - ``engine_errors``: names of engines whose step() raised
            this tick
          - ``handled_products``: products owned by engines this tick
        """
        order_counts = {
            product: len(orders)
            for product, orders in results.items()
            if orders
        }
        summary: dict[str, object] = {
            "event": "tick_summary",
            "timestamp": int(timestamp),
            "order_counts": order_counts,
            "conversions": int(conversions),
        }
        if orch_summary is not None:
            summary["engines"] = (
                self.orchestrator.engine_count
                if self.orchestrator is not None else 0
            )
            if orch_summary.errored_engines:
                summary["engine_errors"] = list(orch_summary.errored_engines)
            if orch_summary.handled_products:
                summary["handled_products"] = sorted(
                    orch_summary.handled_products
                )
        self.logger.record(summary)

    # ---------------------------------------------------------- per-product

    def _step_product(
        self,
        *,
        product: str,
        snapshot: NormalizedSnapshot,
        memory: ProductMemory,
        product_config: ProductConfig,
        strategy: "BaseStrategy",
        timestamp: int,
        portfolio=None,
    ) -> list[Order]:
        # Lazy import: R3 bundles that skip per-product dispatch never
        # reach this code path and therefore never load strategies.base.

        # Observational flow scan — never alters strategy behaviour.
        flow_report = self.flow_analyzer.scan(snapshot, memory)

        # Strategies that opt into cross-product state receive the
        # PortfolioSnapshot and the orchestrator's SignalBus via
        # StrategyContext. Legacy single-product strategies ignore these
        # optional fields.
        signal_bus = (
            self.orchestrator.signal_bus if self.orchestrator is not None else None
        )
        context = StrategyContext(
            product=product,
            snapshot=snapshot,
            memory=memory,
            config=product_config,
            portfolio=portfolio,
            signal_bus=signal_bus,
        )
        intent = strategy.generate_intent(context)
        raw_orders = self.execution_engine.generate_orders(snapshot, intent, product_config)
        raw_orders = self.residual_allocator.augment_orders(
            product=product,
            orders=raw_orders,
            snapshot=snapshot,
            fair_value=intent.fair_value.price,
            position=snapshot.position,
            limit=product_config.position_limit,
            mode=intent.mode,
        )
        legal_orders = self.risk_manager.clip_orders(
            product=product,
            orders=raw_orders,
            current_position=snapshot.position,
            limit=product_config.position_limit,
        )

        event: dict[str, object] = {
            "timestamp": timestamp,
            "product": product,
            "fair_value": round(intent.fair_value.price, 4),
            "method": intent.fair_value.method,
            "position": snapshot.position,
            "mode": intent.mode,
            "orders": [(order.price, order.quantity) for order in legal_orders],
        }
        if flow_report is not None:
            verbosity = self.config.scanner_config.verbosity
            if verbosity >= 2:
                event["flow_report"] = {
                    "net_flow": flow_report.net_flow,
                    "flow_score": flow_report.flow_score,
                    "near_high": flow_report.near_high,
                    "near_low": flow_report.near_low,
                    "flags": list(flow_report.flags),
                    "repeated_sizes": dict(flow_report.repeated_sizes),
                }
            elif verbosity >= 1:
                event["scan_flags"] = list(flow_report.flags)
        self.logger.record(event)
        return legal_orders

    @staticmethod
    def _maybe_flush_for_day_rollover(
        *,
        memory: ProductMemory,
        snapshot: NormalizedSnapshot,
        product_config: ProductConfig,
    ) -> None:
        """Detect a day boundary and flush stale rolling history.

        IMC Prosperity restarts ``snapshot.timestamp`` at 0 on each new
        simulated day. For products whose fair value depends on a
        recent-mids fit (PEPPER's ``linear_drift``), retaining the
        previous day's mids across the rollover mis-anchors the line
        and produces large warm-up errors on the first ~30 ticks.

        Detection rule: if the new ``snapshot.timestamp`` is strictly
        less than the last one we saw for this product, the simulator
        has rolled over. We then clear ``recent_mids`` and
        ``recent_spreads`` so the estimator cold-starts cleanly.
        ``counters``, ``flags`` and ``values`` are left untouched —
        any strategy that needs day-scoped state owns its own reset.
        """
        if not product_config.flush_history_on_day_rollover:
            return
        last_seen = memory.counters.get(_LAST_SEEN_TIMESTAMP_KEY)
        if last_seen is None:
            return
        if snapshot.timestamp >= last_seen:
            return
        memory.recent_mids.clear()
        memory.recent_spreads.clear()

    @staticmethod
    def _update_memory(
        memory: ProductMemory, snapshot: NormalizedSnapshot, history_length: int
    ) -> None:
        if history_length <= 0:
            return
        if snapshot.mid is not None:
            bounded_append(memory.recent_mids, float(snapshot.mid), history_length)
        if snapshot.spread is not None:
            bounded_append(memory.recent_spreads, float(snapshot.spread), history_length)

    # ---------------------------------------------------------- helpers

    def reset(self) -> None:
        """Drop any transient in-memory state (diagnostics only)."""
        self.logger = DecisionLogger()

    def engine_state_from(self, trader_data: str | None) -> EngineState:
        """Expose the state store to callers that need to inspect memory."""
        return self.state_store.load(trader_data)

