"""R3 product constants, position limits, and time-to-expiry helper.

These are the only product-specific constants that belong in the live
submission bundle. Everything else (EDA notes, calibration results,
replay utilities) lives outside the live path.
"""


# ----------------------------------------------------------------- symbols

HYDROGEL_PACK: str = "HYDROGEL_PACK"
VELVETFRUIT_EXTRACT: str = "VELVETFRUIT_EXTRACT"

VOUCHER_STRIKES: tuple[int, ...] = (
    4000, 4500, 5000, 5100, 5200, 5300, 5400, 5500, 6000, 6500,
)

VOUCHER_PRODUCTS: tuple[str, ...] = tuple(
    f"VELVET_VOUCHER_{k}" for k in VOUCHER_STRIKES
)

# R3 data/position reference names (as they appear in the CSV and
# Prosperity TradingState). Vouchers are named VEV_<strike>.
VEV_PRODUCTS: tuple[str, ...] = tuple(f"VEV_{k}" for k in VOUCHER_STRIKES)

# Convenience map: strike → product symbol
STRIKE_TO_PRODUCT: dict[int, str] = {k: f"VEV_{k}" for k in VOUCHER_STRIKES}
PRODUCT_TO_STRIKE: dict[str, int] = {v: k for k, v in STRIKE_TO_PRODUCT.items()}

# ---------------------------------------------------------------- limits

POS_LIMITS: dict[str, int] = {
    HYDROGEL_PACK: 200,
    VELVETFRUIT_EXTRACT: 200,
    **{f"VEV_{k}": 300 for k in VOUCHER_STRIKES},
}

ALL_R3_PRODUCTS: frozenset[str] = frozenset(POS_LIMITS)

# ---------------------------------------------------------------- TTE

# TTE at R3 *final simulation* start = 5 days.
# Timestamps run 0 → 999_900 in steps of 100.
# Each 1_000_000 ticks = 1 calendar day of simulation.
TTE_DAYS_AT_R3_START: float = 5.0
TICKS_PER_DAY: int = 1_000_000


def tte_live(timestamp: int) -> float:
    """Time to expiry in days at ``timestamp`` within R3.

    The live sim starts with TTE = 5.0 at ts = 0. Each 1_000_000
    ticks consume 1 day. Returns a positive value throughout the round;
    clipped to 1e-6 to avoid BSM singularity at expiry.
    """
    remaining = TTE_DAYS_AT_R3_START - timestamp / TICKS_PER_DAY
    return max(remaining, 1e-6)

# ========================================================================
# src/core/primitives/sst.py
# ========================================================================

"""Shared Take / Clear / Make execution primitive.

Ported from the convergent pattern observed across P2/P3 top-team repos
(Linear Utility round_1_v6.py:14-310, Sylvain-Topeza, pe049395). Every
R3+ strategy builds on this scaffold instead of re-implementing quote
placement from scratch.

The primitive is a pure function: given a fair value, an order-book
snapshot, current position, and config, it returns a trading decision
(taker orders + maker quotes). No side effects. No mutable state. All
state lives on the caller side.

Three phases executed in order:

1. **Take.** Cross the spread when the opponent's best-opposite quote is
   more favorable than ``fair ± take_width``. Size is bounded by the
   opponent's displayed volume and our remaining capacity.

2. **Clear.** When inventory is ≥ ``clear_threshold`` of the position
   limit, actively seek to flatten: tighten the unwinding-side quote
   to ``fair`` (zero-edge); widen the building-side quote or suppress it.

3. **Make.** Place passive quotes at ``fair ∓ default_edge``, optionally
   joining the opponent if they're within ``join_edge``. Skews quotes
   away from the adverse-selection side when toxic prints are detected.

The primitive knows nothing about fair-value computation, signals, or
cross-product state — those are the caller's responsibility. It only
knows how to translate "fair + inventory + book" into "orders".
"""




TradingSide = Literal["buy", "sell"]


@dataclass(frozen=True)
class SSTParams:
    """Take / Clear / Make parameters.

    All widths / edges are in *ticks* (integer price units). They must
    all be non-negative. ``disregard_edge`` and ``join_edge`` are
    sub-widths applied to the maker-quote placement decision.
    """

    # Take phase
    take_width: float = 1.0
    """Cross the spread if opponent best is beyond fair ± take_width."""

    # Clear phase
    clear_threshold: float = 0.5
    """|position| / limit >= this ⇒ active unwind mode."""

    clear_width: float = 1.0
    """In clear mode, accept fills within this edge to reduce inventory."""

    # Make phase
    default_edge: float = 2.0
    """Base maker quote offset from fair when no opponent to join."""

    disregard_edge: float = 1.0
    """Ignore opponent quotes within this edge (likely us or penny-jumpers)."""

    join_edge: float = 2.0
    """Join the opponent quote if they're within this edge of fair."""

    # Size controls
    default_quote_size: int = 20
    """Base quote size per side when not adjusted by inventory / toxicity."""

    max_taker_size: int = 30
    """Maximum size taken per cross-spread action."""

    # Adverse-selection filter (D9 in R3+ architecture)
    prevent_adverse: bool = True
    """Skew quotes away from side where recent prints are toxic (size ≤ 2)."""

    toxic_size_threshold: int = 2
    """Prints at or below this size count as toxic."""

    # -------------------- Quote-inside-wall (Stanford / TimoDiehm pattern)
    # When enabled, the Make phase places quotes one tick INSIDE the
    # largest-volume level on each side, rather than at ``fair ± edge``
    # or joining a visible wall. The wall absorbs toxic flow; we capture
    # the remaining spread. F2 finding: this pattern consistently beat
    # edge-from-fair maker pricing on stable R1/R2 products.
    quote_inside_wall: bool = False
    """If True, Make phase pegs quotes 1 tick inside the side's wall."""

    wall_min_volume: int = 10
    """Minimum volume for a level to qualify as a wall."""

    def __post_init__(self) -> None:
        for name, value in [
            ("take_width", self.take_width),
            ("clear_width", self.clear_width),
            ("default_edge", self.default_edge),
            ("disregard_edge", self.disregard_edge),
            ("join_edge", self.join_edge),
        ]:
            if value < 0:
                raise ValueError(f"SSTParams.{name} must be >= 0 (got {value})")
        if not 0.0 <= self.clear_threshold <= 1.0:
            raise ValueError("SSTParams.clear_threshold must be in [0, 1]")
        if self.default_quote_size <= 0:
            raise ValueError("SSTParams.default_quote_size must be > 0")
        if self.max_taker_size <= 0:
            raise ValueError("SSTParams.max_taker_size must be > 0")


@dataclass(frozen=True)
class TradingDecision:
    """Output of the SST primitive.

    Caller wraps this into a ``SignalIntent`` or emits orders directly.
    """

    product: str
    orders: list[Order] = field(default_factory=list)
    mode: ExecutionMode = "idle"
    bid_quote: tuple[int, int] | None = None  # (price, size) — for metadata
    ask_quote: tuple[int, int] | None = None
    rationale: str = ""
    metadata: dict[str, float | int | str | bool] = field(default_factory=dict)


# ============================================================= helpers


def _capacity(position: int, limit: int) -> tuple[int, int]:
    """Return (remaining_buy, remaining_sell) capacity."""
    return (max(0, limit - position), max(0, limit + position))


def _is_toxic(snapshot: NormalizedSnapshot, threshold: int) -> tuple[bool, bool]:
    """Check whether recent prints indicate adverse selection on each side.

    Returns ``(buy_side_toxic, sell_side_toxic)``. A side is toxic if
    recent market trades on that side had sizes ≤ ``threshold`` (small
    probing prints). Conservative: returns ``(False, False)`` if no
    trade tape exists.
    """
    if not snapshot.trades:
        return False, False
    # Snapshot.trades may include our own fills; we only care about market.
    market_trades = tuple(t for t in snapshot.trades if t.source == "market")
    if not market_trades:
        return False, False
    # Mid-of-best as reference for side classification.
    if snapshot.best_bid is None or snapshot.best_ask is None:
        return False, False
    mid = (snapshot.best_bid.price + snapshot.best_ask.price) / 2.0
    buy_toxic = any(
        t.quantity <= threshold and t.price > mid for t in market_trades
    )
    sell_toxic = any(
        t.quantity <= threshold and t.price < mid for t in market_trades
    )
    return buy_toxic, sell_toxic


def _pick_wall_level(
    side_levels: tuple[BookLevel, ...],
    min_volume: int,
) -> BookLevel | None:
    """Return the largest-volume level on a side whose volume >= min_volume.

    Ties broken by closeness to the touch (first in ``side_levels``).
    Returns ``None`` if no qualifying level exists. Used by the
    quote-inside-wall pattern: the wall is the level we shelter behind.
    """
    if not side_levels:
        return None
    best: BookLevel | None = None
    best_vol = -1
    for level in side_levels:
        if level.volume < min_volume:
            continue
        if level.volume > best_vol:
            best, best_vol = level, level.volume
    return best


def _pick_join_level(
    side_levels: tuple[BookLevel, ...],
    fair: float,
    disregard: float,
    join: float,
    side: TradingSide,
) -> BookLevel | None:
    """Pick an opponent level to join, or None if there's no good candidate.

    Walks the side's levels from best inward. Skips levels within
    ``disregard`` of fair (likely us or penny-jumpers). Joins the first
    level within ``join`` of fair.
    """
    for level in side_levels:
        distance = abs(level.price - fair)
        if distance <= disregard:
            continue
        if distance <= join:
            return level
        return None  # levels beyond join-edge won't be nearer on next iter
    return None


# ========================================================== primary API


def take_clear_make(
    *,
    product: str,
    fair_value: float,
    snapshot: NormalizedSnapshot,
    position: int,
    position_limit: int,
    params: SSTParams,
) -> TradingDecision:
    """Compute orders for one tick under the SST protocol.

    Pure function. No side effects. Deterministic given inputs.
    """
    if position_limit <= 0:
        raise ValueError("position_limit must be > 0")
    if fair_value <= 0:
        # Protect against zero_fallback FV. Caller should surface this
        # as a crash condition, but here we just abstain from trading.
        return TradingDecision(product=product, mode="idle", rationale="invalid_fair")

    buy_cap, sell_cap = _capacity(position, position_limit)
    pos_ratio = position / position_limit
    flattening = abs(pos_ratio) >= params.clear_threshold

    orders: list[Order] = []
    rationale_parts: list[str] = []
    meta: dict[str, float | int | str | bool] = {
        "fair_value": round(fair_value, 2),
        "position_ratio": round(pos_ratio, 4),
        "flattening": flattening,
    }

    # -------------------------------- Phase 1: TAKE
    buy_take_threshold = fair_value - params.take_width
    sell_take_threshold = fair_value + params.take_width

    # Take buy: opponent ask below buy_take_threshold.
    if snapshot.best_ask is not None and buy_cap > 0:
        if snapshot.best_ask.price <= buy_take_threshold:
            size = min(snapshot.best_ask.volume, buy_cap, params.max_taker_size)
            if size > 0:
                orders.append(Order(product, snapshot.best_ask.price, size))
                buy_cap -= size
                rationale_parts.append(f"take_buy@{snapshot.best_ask.price}x{size}")

    # Take sell: opponent bid above sell_take_threshold.
    if snapshot.best_bid is not None and sell_cap > 0:
        if snapshot.best_bid.price >= sell_take_threshold:
            size = min(snapshot.best_bid.volume, sell_cap, params.max_taker_size)
            if size > 0:
                orders.append(Order(product, snapshot.best_bid.price, -size))
                sell_cap -= size
                rationale_parts.append(f"take_sell@{snapshot.best_bid.price}x{size}")

    # -------------------------------- Phase 2: CLEAR
    if flattening:
        if position > 0 and sell_cap > 0:
            # Long inventory — actively unwind at fair.
            clear_price = int(math.ceil(fair_value - params.clear_width))
            # Only clear if the price is reachable by matching opponent bid.
            if snapshot.best_bid is not None and clear_price <= snapshot.best_bid.price:
                size = min(position, sell_cap, params.max_taker_size)
                if size > 0:
                    orders.append(Order(product, snapshot.best_bid.price, -size))
                    sell_cap -= size
                    rationale_parts.append(f"clear_sell@{snapshot.best_bid.price}x{size}")
        elif position < 0 and buy_cap > 0:
            # Short inventory — actively cover at fair.
            clear_price = int(math.floor(fair_value + params.clear_width))
            if snapshot.best_ask is not None and clear_price >= snapshot.best_ask.price:
                size = min(-position, buy_cap, params.max_taker_size)
                if size > 0:
                    orders.append(Order(product, snapshot.best_ask.price, size))
                    buy_cap -= size
                    rationale_parts.append(f"clear_buy@{snapshot.best_ask.price}x{size}")

    # -------------------------------- Phase 3: MAKE
    # Detect toxic flow.
    buy_toxic, sell_toxic = (False, False)
    if params.prevent_adverse:
        buy_toxic, sell_toxic = _is_toxic(snapshot, params.toxic_size_threshold)
        meta["buy_toxic"] = buy_toxic
        meta["sell_toxic"] = sell_toxic

    bid_quote: tuple[int, int] | None = None
    ask_quote: tuple[int, int] | None = None

    # Decide maker bid price.
    if buy_cap > 0 and not (flattening and position > 0):
        bid_price = int(math.floor(fair_value - params.default_edge))
        if params.quote_inside_wall:
            # F2 inside-wall pattern: peg one tick closer to mid than the
            # side's wall. The wall shelters us from toxic flow; we
            # capture the remaining spread. Falls back to edge-from-fair
            # if no wall meets wall_min_volume.
            wall_bid = _pick_wall_level(snapshot.bids, params.wall_min_volume)
            if wall_bid is not None:
                bid_price = wall_bid.price + 1
        else:
            join = _pick_join_level(
                snapshot.bids, fair_value, params.disregard_edge,
                params.join_edge, "buy",
            )
            if join is not None:
                # Join by placing at the same price (or inside if allowed).
                bid_price = max(bid_price, join.price)
        # Widen if buy side is toxic.
        if buy_toxic:
            bid_price -= 1
        # Don't cross the spread.
        if snapshot.best_ask is not None:
            bid_price = min(bid_price, snapshot.best_ask.price - 1)
        bid_size = min(params.default_quote_size, buy_cap)
        # In clear mode with long position, suppress bid entirely.
        if flattening and position > 0:
            bid_size = 0
        if bid_size > 0 and bid_price > 0:
            orders.append(Order(product, bid_price, bid_size))
            bid_quote = (bid_price, bid_size)
            rationale_parts.append(f"make_bid@{bid_price}x{bid_size}")

    # Decide maker ask price.
    if sell_cap > 0 and not (flattening and position < 0):
        ask_price = int(math.ceil(fair_value + params.default_edge))
        if params.quote_inside_wall:
            wall_ask = _pick_wall_level(snapshot.asks, params.wall_min_volume)
            if wall_ask is not None:
                ask_price = wall_ask.price - 1
        else:
            join = _pick_join_level(
                snapshot.asks, fair_value, params.disregard_edge,
                params.join_edge, "sell",
            )
            if join is not None:
                ask_price = min(ask_price, join.price)
        if sell_toxic:
            ask_price += 1
        if snapshot.best_bid is not None:
            ask_price = max(ask_price, snapshot.best_bid.price + 1)
        ask_size = min(params.default_quote_size, sell_cap)
        if flattening and position < 0:
            ask_size = 0
        if ask_size > 0 and ask_price > 0:
            orders.append(Order(product, ask_price, -ask_size))
            ask_quote = (ask_price, ask_size)
            rationale_parts.append(f"make_ask@{ask_price}x{ask_size}")

    # -------------------------------- Assemble decision
    if not orders:
        mode: ExecutionMode = "idle"
    elif flattening:
        mode = "recovery"
    elif any("take" in r for r in rationale_parts):
        mode = "hybrid"
    else:
        mode = "maker"

    return TradingDecision(
        product=product,
        orders=orders,
        mode=mode,
        bid_quote=bid_quote,
        ask_quote=ask_quote,
        rationale=";".join(rationale_parts) if rationale_parts else "idle",
        metadata=meta,
    )

# ========================================================================
# src/core/primitives/terminal_ramp.py
# ========================================================================

"""Terminal risk ramp — linear inventory-band scaling as end-of-round approaches.

Plan G spec:
  t < 850_000   → scale = 1.0  (full bands)
  t in [850K, 950K) → scale = (950_000 - t) / 100_000  (linear decay)
  t >= 950_000  → scale = 0.0  (fully flat)

The ZeroBidLottery (VEV_6000 / VEV_6500) is exempt from this ramp —
0-cost fills carry no end-of-round mark risk.
"""


_RAMP_START: int = 850_000
_RAMP_END: int = 950_000
_RAMP_WIDTH: float = float(_RAMP_END - _RAMP_START)

# Products exempt from the ramp (0-cost lottery orders).
RAMP_EXEMPT_PRODUCTS: frozenset[str] = frozenset({"VEV_6000", "VEV_6500"})


def scale_factor(timestamp: int) -> float:
    """Inventory-band scaling factor at ``timestamp``.

    Returns 1.0 before the ramp, 0.0 after, linear in between.
    """
    if timestamp < _RAMP_START:
        return 1.0
    if timestamp >= _RAMP_END:
        return 0.0
    return (_RAMP_END - timestamp) / _RAMP_WIDTH


def scaled_cap(base_cap: int, timestamp: int) -> int:
    """Apply the ramp to a position cap, returning at least 1 (avoids div-by-zero)."""
    sf = scale_factor(timestamp)
    result = int(base_cap * sf)
    return max(result, 1)


def is_in_ramp(timestamp: int) -> bool:
    return timestamp >= _RAMP_START


def is_post_ramp(timestamp: int) -> bool:
    return timestamp >= _RAMP_END

# ========================================================================
# src/core/primitives/r3_delta_budget.py
# ========================================================================

"""Aggregate delta/gamma budget for R3 (Plan H).

Coordinates VELVETFRUIT_EXTRACT, VEV_4000, and OTM voucher positions so
their combined net delta never exceeds the session cap. Called by the
R3Engine before order submission.

Priority when multiple engines compete for the remaining capacity:
    HYDROGEL (no delta) > VEV_4000 (delta=1.0) > OTM vouchers (delta<1)

Cap schedule:
    t <  850_000  →  soft ±80,  hard ±130
    t >= 850_000  →  terminal ±40  (ramp in sync with TerminalRamp)
"""




# ------------------------------------------------------------------ caps

TERMINAL_START: int = 850_000


@dataclass(frozen=True)
class DeltaCaps:
    soft: int = 80
    hard: int = 130
    terminal: int = 40


DEFAULT_CAPS: DeltaCaps = DeltaCaps()


# ----------------------------------------------------------------- deltas

def _voucher_delta(strike: int, spot: float | None) -> float:
    """Approximate BSM delta for deep-ITM/ATM/OTM vouchers.

    VEV_4000 is always treated as delta=1.0 (see EXECUTION_GUIDE pitfall #8).
    ATM/OTM strikes use a linear approximation based on moneyness.
    The SmileCache provides more accurate deltas when available; this
    is the fallback used when SmileCache has not warmed up yet.
    """
    if strike == 4000:
        return 1.0
    if spot is None or spot <= 0:
        return 0.5  # unknown; conservative
    moneyness = spot / strike
    # Rough approximation: delta ≈ N(d1) ≈ sigmoid-like on moneyness
    if moneyness >= 1.10:
        return 0.85
    if moneyness >= 1.02:
        return 0.70
    if moneyness >= 0.98:
        return 0.50
    if moneyness >= 0.90:
        return 0.25
    return 0.10


# ----------------------------------------------------------------- class

class R3DeltaBudget:
    """Tracks and enforces net-delta cap across all R3 products.

    Usage per tick:
        budget = R3DeltaBudget()
        budget.update_positions(positions, spot)
        remaining = budget.remaining_capacity(timestamp)
        safe_orders = budget.enforce(intended_orders, timestamp, positions, spot)
    """

    def __init__(self, caps: DeltaCaps = DEFAULT_CAPS) -> None:
        self._caps = caps
        # Cached delta estimates per voucher strike (updated by SmileCache
        # if available; falls back to _voucher_delta otherwise).
        self._strike_deltas: dict[int, float] = {
            k: 0.5 for k in VOUCHER_STRIKES
        }
        self._strike_deltas[4000] = 1.0  # invariant

    def set_strike_delta(self, strike: int, delta: float) -> None:
        """Update delta estimate from SmileCache (called once per tick)."""
        if strike == 4000:
            return  # VEV_4000 delta is always exactly 1.0
        self._strike_deltas[strike] = max(0.0, min(1.0, delta))

    def net_delta(
        self,
        positions: dict[str, int],
        spot: float | None = None,
    ) -> float:
        """Compute current net delta across all R3 products.

        net_delta = VELVET_pos
                  + VEV_4000_pos × 1.0
                  + Σ(voucher_pos[K] × delta[K])
        """
        nd: float = float(positions.get(VELVETFRUIT_EXTRACT, 0))
        for k in VOUCHER_STRIKES:
            product = f"VEV_{k}"
            pos = positions.get(product, 0)
            if pos != 0:
                delta = self._strike_deltas.get(k, _voucher_delta(k, spot))
                nd += pos * delta
        return nd

    def _cap_for(self, timestamp: int) -> int:
        if timestamp >= TERMINAL_START:
            return self._caps.terminal
        return self._caps.hard

    def remaining_capacity(
        self,
        timestamp: int,
        positions: dict[str, int],
        spot: float | None = None,
    ) -> int:
        """Signed remaining delta budget (positive = can add long delta)."""
        cap = self._cap_for(timestamp)
        nd = self.net_delta(positions, spot)
        # How far we are from the cap in each direction.
        long_room = cap - nd
        short_room = cap + nd
        return int(min(long_room, short_room))

    def enforce(
        self,
        intended_orders: list[Order],
        timestamp: int,
        positions: dict[str, int],
        spot: float | None = None,
    ) -> list[Order]:
        """Filter orders that would push net delta beyond the hard cap.

        Returns orders that are allowed. Orders that would cause a
        cap breach are dropped (not clipped — the strategy re-quotes
        next tick with the correct cap in mind).

        HYDROGEL orders pass through unchanged (no delta).
        VELVET orders are treated as delta-1 for cap purposes.
        VEV_4000 delta = 1.0. Other vouchers use cached deltas.
        """
        cap = self._cap_for(timestamp)
        nd = self.net_delta(positions, spot)

        safe: list[Order] = []
        for order in intended_orders:
            symbol = order.symbol
            qty = order.quantity  # positive = buy, negative = sell

            # HYDROGEL never contributes delta.
            if symbol == "HYDROGEL_PACK":
                safe.append(order)
                continue

            # Determine how much delta this order would add.
            strike = PRODUCT_TO_STRIKE.get(symbol)
            if symbol == VELVETFRUIT_EXTRACT:
                delta_per_unit = 1.0
            elif strike is not None:
                delta_per_unit = self._strike_deltas.get(
                    strike, _voucher_delta(strike, spot)
                )
            else:
                safe.append(order)
                continue

            order_delta = qty * delta_per_unit
            new_nd = nd + order_delta

            if abs(new_nd) <= cap:
                safe.append(order)
                nd = new_nd  # update running tally
            # else: drop this order — cap would be breached

        return safe

    def to_state(self) -> dict:
        return {"strike_deltas": dict(self._strike_deltas)}

    def from_state(self, blob: dict) -> None:
        saved = blob.get("strike_deltas", {})
        for k_str, v in saved.items():
            try:
                k = int(k_str)
                if k in self._strike_deltas and k != 4000:
                    self._strike_deltas[k] = float(v)
            except (ValueError, TypeError):
                pass

# ========================================================================
# src/options/bsm.py
# ========================================================================

"""Black-Scholes-Merton option pricing (fixes D7 for options).

Pure Python implementation with inline Abramowitz-Stegun (1964) approximation
for the standard normal CDF — scipy is NOT available in the Prosperity
submission container.

Only call options are implemented (Prosperity vouchers are calls in P3;
extend to puts when/if needed).

All functions are pure. No state, no I/O.

Reference: `engine_options.md` §2 for design decisions. The A&S 7.1.26
approximation is accurate to ~7.5e-8 — more than enough for voucher
pricing where the tick-grid rounds to 1 anyway.
"""




# ============================================================= norm CDF


# Abramowitz & Stegun 7.1.26 coefficients.
_A1 = 0.254829592
_A2 = -0.284496736
_A3 = 1.421413741
_A4 = -1.453152027
_A5 = 1.061405429
_P = 0.3275911


def norm_cdf(x: float) -> float:
    """Standard normal CDF, Abramowitz-Stegun 7.1.26 approximation.

    Accurate to ~7.5e-8. Symmetric: uses identity Φ(-x) = 1 - Φ(x).
    """
    sign = 1 if x >= 0 else -1
    abs_x = abs(x) / math.sqrt(2.0)
    t = 1.0 / (1.0 + _P * abs_x)
    y = 1.0 - (((((_A5 * t + _A4) * t) + _A3) * t + _A2) * t + _A1) * t * math.exp(
        -abs_x * abs_x
    )
    return 0.5 * (1.0 + sign * y)


def norm_pdf(x: float) -> float:
    """Standard normal PDF."""
    return math.exp(-0.5 * x * x) / math.sqrt(2.0 * math.pi)


# ============================================================= BSM call


@dataclass(frozen=True)
class BSMInputs:
    """Inputs to the Black-Scholes-Merton formula.

    Time-to-expiry is in YEARS (or whatever unit matches the vol
    annualization). Prosperity vouchers: if expiry is in 'ticks' and
    vol is per-tick, T stays in ticks. If vol is daily, T in days. The
    caller must be consistent.
    """

    spot: float
    """Underlying price S."""

    strike: float
    """Strike price K."""

    time_to_expiry: float
    """T — time until expiration, in units matching volatility."""

    volatility: float
    """σ — standard deviation per unit time (same unit as T)."""

    risk_free_rate: float = 0.0
    """r — assumed 0 in Prosperity (no cash leg accrues interest)."""

    def __post_init__(self) -> None:
        if self.spot <= 0:
            raise ValueError("spot must be > 0")
        if self.strike <= 0:
            raise ValueError("strike must be > 0")
        if self.time_to_expiry <= 0:
            raise ValueError("time_to_expiry must be > 0")
        if self.volatility <= 0:
            raise ValueError("volatility must be > 0")


def _d1_d2(inputs: BSMInputs) -> tuple[float, float]:
    sigma_sqrt_t = inputs.volatility * math.sqrt(inputs.time_to_expiry)
    d1 = (
        math.log(inputs.spot / inputs.strike)
        + (inputs.risk_free_rate + 0.5 * inputs.volatility ** 2) * inputs.time_to_expiry
    ) / sigma_sqrt_t
    d2 = d1 - sigma_sqrt_t
    return d1, d2


def call_price(inputs: BSMInputs) -> float:
    """Black-Scholes call price."""
    d1, d2 = _d1_d2(inputs)
    return (
        inputs.spot * norm_cdf(d1)
        - inputs.strike
        * math.exp(-inputs.risk_free_rate * inputs.time_to_expiry)
        * norm_cdf(d2)
    )


# ============================================================= Greeks


@dataclass(frozen=True)
class Greeks:
    """Option Greeks for a call."""

    delta: float  # ∂C/∂S
    gamma: float  # ∂²C/∂S²
    vega: float   # ∂C/∂σ (per 1.00 absolute change in vol, not per %)
    theta: float  # ∂C/∂T (per unit of T)


def call_greeks(inputs: BSMInputs) -> Greeks:
    """Compute delta/gamma/vega/theta for a call.

    Theta is returned per UNIT of time-to-expiry (negative, since
    extrinsic value decays). If T is in days, theta is per-day.
    """
    d1, d2 = _d1_d2(inputs)
    sqrt_t = math.sqrt(inputs.time_to_expiry)
    pdf_d1 = norm_pdf(d1)

    delta = norm_cdf(d1)
    gamma = pdf_d1 / (inputs.spot * inputs.volatility * sqrt_t)
    vega = inputs.spot * pdf_d1 * sqrt_t
    theta = (
        -inputs.spot * pdf_d1 * inputs.volatility / (2.0 * sqrt_t)
        - inputs.risk_free_rate
        * inputs.strike
        * math.exp(-inputs.risk_free_rate * inputs.time_to_expiry)
        * norm_cdf(d2)
    )
    return Greeks(delta=delta, gamma=gamma, vega=vega, theta=theta)


# ============================================================= IV solver


def implied_vol(
    market_price: float,
    *,
    spot: float,
    strike: float,
    time_to_expiry: float,
    risk_free_rate: float = 0.0,
    lo: float = 0.001,
    hi: float = 5.0,
    tol: float = 1e-6,
    max_iter: int = 60,
) -> float | None:
    """Bisection-based IV solver.

    Returns None if no IV in [lo, hi] produces a call price matching
    market_price (e.g., market_price below intrinsic or above cap).
    """
    if market_price <= 0:
        return None
    intrinsic = max(0.0, spot - strike * math.exp(-risk_free_rate * time_to_expiry))
    if market_price < intrinsic - tol:
        return None  # arbitrage or misquote
    if spot <= 0 or strike <= 0 or time_to_expiry <= 0:
        return None

    def f(sigma: float) -> float:
        inputs = BSMInputs(
            spot=spot, strike=strike, time_to_expiry=time_to_expiry,
            volatility=sigma, risk_free_rate=risk_free_rate,
        )
        return call_price(inputs) - market_price

    f_lo = f(lo)
    f_hi = f(hi)

    # Exact-bracket endpoints: if f(lo) or f(hi) is already within tolerance,
    # return that value directly. CRITICAL fix: `f_lo * f_mid < 0` becomes
    # vacuously false when f_lo == 0, causing the solver to converge on `hi`
    # for deep-ITM options where call_price(sigma=lo) already matches market.
    if abs(f_lo) < tol:
        return lo
    if abs(f_hi) < tol:
        return hi

    # Monotonic in sigma; need sign change to bracket root.
    if f_lo * f_hi > 0:
        # Root is outside [lo, hi]. Try widening hi up to 10 once.
        if f_hi < 0 and hi < 10.0:
            wider = 10.0
            f_wider = f(wider)
            if f_wider > 0:
                hi = wider
                f_hi = f_wider
            else:
                return None
        else:
            return None

    for _ in range(max_iter):
        mid = 0.5 * (lo + hi)
        f_mid = f(mid)
        if abs(f_mid) < tol:
            return mid
        if f_lo * f_mid < 0:
            hi = mid
            f_hi = f_mid
        else:
            lo = mid
            f_lo = f_mid
    return 0.5 * (lo + hi)

# ========================================================================
# src/options/smile.py
# ========================================================================

"""IV smile fitter with graceful degradation (fixes D2 for options).

F1 forensic showed chrispyroberts' quadratic smile BROKE on submission
day — a single quadratic overfits in-sample and fails OOS. His team
switched to rolling mid-IV mid-round and doubled P&L (80k → 200k/day).

Our fitter implements BOTH in a degradation chain:

- **Warmup mode** (obs per strike < 50): fit quadratic in moneyness.
  Returns a fitted IV per strike.
- **Rolling mode** (obs per strike ≥ 50): use the rolling-mean mid-IV
  per strike with an EWMA halflife. More robust to regime changes.

The degradation is AUTOMATIC — the caller always asks for `fair_iv(strike)`
and the fitter picks the right mode internally. No config flag needed
to switch between modes.

Moneyness is computed as `m = log(K/S) / sqrt(T)` per Gatheral-Jacquier.

Pure Python; no numpy or scipy. The polynomial fit uses normal
equations on 3x3 matrices.
"""




@dataclass(frozen=True)
class SmileConfig:
    """Smile fitter configuration."""

    warmup_threshold: int = 50
    """Minimum observations per strike before switching off quadratic warmup."""

    rolling_window: int = 200
    """Lookback for the rolling-mid-IV mode."""

    ewma_halflife: float = 100.0
    """EWMA halflife for the rolling mode (ticks)."""

    max_sensible_iv: float = 2.0
    """Reject IV observations above this (likely solver failures)."""

    min_sensible_iv: float = 0.01
    """Reject IV observations below this."""

    def __post_init__(self) -> None:
        if self.warmup_threshold <= 0:
            raise ValueError("warmup_threshold must be > 0")
        if self.rolling_window <= 0:
            raise ValueError("rolling_window must be > 0")
        if self.ewma_halflife <= 0:
            raise ValueError("ewma_halflife must be > 0")


def moneyness(strike: float, spot: float, time_to_expiry: float) -> float:
    """Gatheral-Jacquier moneyness: m = log(K/S) / sqrt(T)."""
    if spot <= 0 or time_to_expiry <= 0:
        raise ValueError("spot and time_to_expiry must be > 0")
    return math.log(strike / spot) / math.sqrt(time_to_expiry)


# =============================================================== fitter


@dataclass
class SmileFitter:
    """Accumulates IV observations per strike and fits a smile.

    Holds one deque per strike and an EWMA state. Query ``fair_iv``
    with a strike (and current spot+T for moneyness) to get the
    fitted IV.

    State is mutable but self-contained; serialized via ``snapshot``
    for traderData persistence.
    """

    config: SmileConfig = field(default_factory=SmileConfig)
    # strike -> deque of recent IV observations
    _per_strike_iv: dict[float, deque[float]] = field(default_factory=dict)
    # strike -> EWMA rolling IV
    _ewma_iv: dict[float, float] = field(default_factory=dict)
    # total observations across all strikes (to decide warmup vs rolling)
    _total_obs: int = 0

    def observe(self, strike: float, iv: float) -> None:
        """Feed one IV observation for a strike. Ignores outliers."""
        cfg = self.config
        if iv < cfg.min_sensible_iv or iv > cfg.max_sensible_iv:
            return
        if strike not in self._per_strike_iv:
            self._per_strike_iv[strike] = deque(maxlen=cfg.rolling_window)
        self._per_strike_iv[strike].append(iv)
        # EWMA update.
        alpha = 1.0 - math.exp(math.log(0.5) / cfg.ewma_halflife)
        prev = self._ewma_iv.get(strike)
        self._ewma_iv[strike] = iv if prev is None else alpha * iv + (1 - alpha) * prev
        self._total_obs += 1

    def _in_warmup(self, strike: float) -> bool:
        return (
            strike not in self._per_strike_iv
            or len(self._per_strike_iv[strike]) < self.config.warmup_threshold
        )

    def fair_iv(
        self,
        *,
        strike: float,
        spot: float,
        time_to_expiry: float,
    ) -> float | None:
        """Return the fitted fair IV for this strike, given current S/T.

        Picks rolling mode if observations permit, else warmup mode
        (quadratic fit across strikes if ≥ 3 strikes, else return
        latest obs for this strike).
        """
        if self._in_warmup(strike):
            return self._warmup_iv(strike=strike, spot=spot, time_to_expiry=time_to_expiry)
        return self._ewma_iv.get(strike)

    def _warmup_iv(
        self,
        *,
        strike: float,
        spot: float,
        time_to_expiry: float,
    ) -> float | None:
        """Quadratic fit across strikes on moneyness. Needs ≥ 3 strikes."""
        # Gather (moneyness, mean_iv) pairs across strikes.
        points: list[tuple[float, float]] = []
        for k, samples in self._per_strike_iv.items():
            if not samples:
                continue
            m = moneyness(strike=k, spot=spot, time_to_expiry=time_to_expiry)
            avg_iv = sum(samples) / len(samples)
            points.append((m, avg_iv))
        if not points:
            return None
        if len(points) < 3:
            # Can't fit a quadratic — return last obs for this strike.
            if strike in self._per_strike_iv and self._per_strike_iv[strike]:
                return self._per_strike_iv[strike][-1]
            return None
        # Fit v = a*m^2 + b*m + c via normal equations.
        coeffs = _fit_quadratic(points)
        if coeffs is None:
            return None
        a, b, c = coeffs
        m_query = moneyness(strike=strike, spot=spot, time_to_expiry=time_to_expiry)
        return a * m_query * m_query + b * m_query + c

    def snapshot(self) -> dict:
        """Serializable snapshot for traderData persistence."""
        return {
            "per_strike_iv": {
                str(k): list(v) for k, v in self._per_strike_iv.items()
            },
            "ewma_iv": {str(k): v for k, v in self._ewma_iv.items()},
            "total_obs": self._total_obs,
        }

    @classmethod
    def restore(cls, payload: dict, config: SmileConfig | None = None) -> SmileFitter:
        cfg = config or SmileConfig()
        fitter = cls(config=cfg)
        raw = payload.get("per_strike_iv", {})
        if isinstance(raw, dict):
            for k, v in raw.items():
                try:
                    strike = float(k)
                    fitter._per_strike_iv[strike] = deque(
                        [float(x) for x in v], maxlen=cfg.rolling_window,
                    )
                except (ValueError, TypeError):
                    continue
        raw_ewma = payload.get("ewma_iv", {})
        if isinstance(raw_ewma, dict):
            for k, v in raw_ewma.items():
                try:
                    fitter._ewma_iv[float(k)] = float(v)
                except (ValueError, TypeError):
                    continue
        fitter._total_obs = int(payload.get("total_obs", 0))
        return fitter


def _fit_quadratic(points: list[tuple[float, float]]) -> tuple[float, float, float] | None:
    """Least-squares quadratic fit v = a*x^2 + b*x + c via normal equations."""
    n = len(points)
    if n < 3:
        return None
    # Normal equations for y = a*x^2 + b*x + c:
    # [Σx^4  Σx^3  Σx^2] [a]   [Σx^2*y]
    # [Σx^3  Σx^2  Σx  ] [b] = [Σx*y  ]
    # [Σx^2  Σx    n   ] [c]   [Σy    ]
    sx = sx2 = sx3 = sx4 = sy = sxy = sx2y = 0.0
    for x, y in points:
        x2 = x * x
        sx += x; sx2 += x2; sx3 += x2 * x; sx4 += x2 * x2
        sy += y; sxy += x * y; sx2y += x2 * y
    matrix = [
        [sx4, sx3, sx2],
        [sx3, sx2, sx],
        [sx2, sx, float(n)],
    ]
    rhs = [sx2y, sxy, sy]
    return _solve_3x3(matrix, rhs)


def _solve_3x3(
    matrix: list[list[float]], rhs: list[float]
) -> tuple[float, float, float] | None:
    """Gaussian elimination for a 3x3 linear system. Returns None if singular."""
    m = [row[:] + [rhs[i]] for i, row in enumerate(matrix)]
    for i in range(3):
        pivot = m[i][i]
        # Partial pivoting.
        max_row = max(range(i, 3), key=lambda r: abs(m[r][i]))
        if max_row != i:
            m[i], m[max_row] = m[max_row], m[i]
            pivot = m[i][i]
        if abs(pivot) < 1e-12:
            return None
        for j in range(i + 1, 3):
            factor = m[j][i] / pivot
            for k in range(i, 4):
                m[j][k] -= factor * m[i][k]
    # Back-substitute.
    x = [0.0, 0.0, 0.0]
    for i in range(2, -1, -1):
        s = m[i][3]
        for j in range(i + 1, 3):
            s -= m[i][j] * x[j]
        x[i] = s / m[i][i]
    return (x[0], x[1], x[2])

# ========================================================================
# src/core/primitives/smile_cache.py
# ========================================================================

"""Per-tick IV smile cache for R3 options.

Wraps SmileFitter + BSM to provide:
  - Per-tick update from observed voucher mid-prices
  - fair(K)  → BSM fair price for strike K
  - delta(K) → BSM delta for strike K
  - iv(K)    → fitted IV for strike K
  - is_corrupt(K) → True if book mid diverges > 2σ from model

Fit-all quadratic on core strikes {5000, 5100, 5200, 5300, 5400, 5500}.
VEV_4000 delta is always 1.0 (see EXECUTION_GUIDE pitfall #8).
Does NOT use leave-one-out residuals in production.
"""




# Core strikes used for smile fitting (skip illiquid extremes)
_FIT_STRIKES: tuple[int, ...] = (5000, 5100, 5200, 5300, 5400, 5500)

# Default IV used before warmup (approx ATM IV from EDA: ~1% daily ≈ sqrt(252)*0.01)
_DEFAULT_IV: float = 0.16  # annualized; adjusted for daily vol at ~1% / day

# Corruption threshold: |book_mid - fair| > _CORRUPT_SIGMA × sigma_IV × vega
_CORRUPT_SIGMA: float = 2.0


class SmileCache:
    """Per-tick smile state. Stateful; one instance per R3 session."""

    def __init__(self, config: SmileConfig | None = None) -> None:
        self._fitter = SmileFitter(
            config=config
            or SmileConfig(
                warmup_threshold=20,
                rolling_window=200,
                ewma_halflife=100.0,
            )
        )
        # Most-recent results (None until first update).
        self._spot: float | None = None
        self._tte: float | None = None
        self._fair: dict[int, float] = {}
        self._delta: dict[int, float] = {4000: 1.0}  # VEV_4000 always 1.0
        self._iv: dict[int, float] = {}
        self._vega: dict[int, float] = {}

    def update(
        self,
        timestamp: int,
        spot: float,
        strike_mids: dict[int, float],
    ) -> None:
        """Feed current tick's mid-prices. Fit smile. Recompute cache.

        ``strike_mids`` maps strike → observed voucher mid-price.
        Missing strikes are skipped (no fill on that tick).
        """
        if spot <= 0:
            return

        tte = tte_live(timestamp)
        self._spot = spot
        self._tte = tte

        # 1. Convert mid-prices to IV and feed the fitter (fit-all only).
        for k in _FIT_STRIKES:
            mid = strike_mids.get(k)
            if mid is None or mid <= 0:
                continue
            intrinsic = max(spot - k, 0.0)
            extrinsic = mid - intrinsic
            if extrinsic <= 0.01:
                continue  # effectively at intrinsic; IV solver unstable
            try:
                iv = implied_vol(
                    mid,
                    spot=spot,
                    strike=float(k),
                    time_to_expiry=tte,
                )
            except (ValueError, RuntimeError, ZeroDivisionError):
                continue
            if iv is not None:
                self._fitter.observe(float(k), iv)

        # 2. Recompute fair / delta / vega for every strike.
        for k in VOUCHER_STRIKES:
            if k == 4000:
                # delta=1.0 always; price tracks intrinsic
                self._delta[k] = 1.0
                self._fair[k] = max(spot - k, 0.0)
                self._iv[k] = float("nan")
                continue

            iv = self._fitter.fair_iv(
                strike=float(k), spot=spot, time_to_expiry=tte
            )
            if iv is None or iv <= 0:
                # Warmup: fall back to default IV
                iv = _DEFAULT_IV

            try:
                inputs = BSMInputs(
                    spot=spot,
                    strike=float(k),
                    time_to_expiry=tte,
                    volatility=iv,
                )
                fair = call_price(inputs)
                greeks = call_greeks(inputs)
            except (ValueError, ZeroDivisionError):
                continue

            self._iv[k] = iv
            self._fair[k] = max(fair, max(spot - k, 0.0))  # floor at intrinsic
            self._delta[k] = max(0.0, min(1.0, greeks.delta))
            self._vega[k] = greeks.vega

    def fair(self, strike: int) -> float | None:
        return self._fair.get(strike)

    def delta(self, strike: int) -> float | None:
        return self._delta.get(strike)

    def iv(self, strike: int) -> float | None:
        return self._iv.get(strike)

    def is_corrupt(self, strike: int, book_mid: float | None) -> bool:
        """Return True if book mid diverges > 2σ from model fair.

        Used as a quoting guard: do not quote if model and book disagree
        strongly (possible microstructure breakdown or expiry).
        """
        if book_mid is None:
            return False
        fair = self._fair.get(strike)
        if fair is None:
            return False
        iv = self._iv.get(strike)
        vega = self._vega.get(strike)
        if iv is None or vega is None or vega == 0:
            return False
        sigma_iv = iv * _CORRUPT_SIGMA
        threshold = sigma_iv * vega
        return abs(book_mid - fair) > max(threshold, 2.0)  # min 2-tick band

    def snapshot(self) -> dict:
        return {
            "fitter": self._fitter.snapshot(),
            "spot": self._spot,
            "tte": self._tte,
        }

    def restore(self, blob: dict) -> None:
        if not blob:
            return
        fitter_blob = blob.get("fitter")
        if fitter_blob:
            self._fitter = SmileFitter.restore(fitter_blob)
        self._spot = blob.get("spot")
        self._tte = blob.get("tte")

