# ========================================================================
# src/strategies/round_3/hydrogel_mm.py
# ========================================================================

"""HYDROGEL_PACK market-maker — Plan A.

Wide-spread (median 16) delta-1 product with balanced flow.
3-day replay: +27,360 at 100% fill. Dominant algorithmic alpha source.

Uses the SST Take/Clear/Make primitive with inventory skew.
Independent of delta budget (HYDROGEL carries no option delta).

Bot shot sizes: {2, 3, 4, 5, 6}. We break large quotes into size-5
child orders for better queue position (Plan L / T13).
"""




# Default SST parameters (post-sweep best from T02b)
_DEFAULT_PARAMS: SSTParams = SSTParams(
    take_width=8.0,
    clear_threshold=0.5,
    clear_width=3.0,
    default_edge=3.0,
    disregard_edge=1.0,
    join_edge=3.0,
    default_quote_size=5,   # size-5 child orders to match bot shot sizes
    max_taker_size=30,
    prevent_adverse=False,  # HYDROGEL flow is balanced; no adverse filter
    quote_inside_wall=True, # F2 convergent pattern
    wall_min_volume=10,
)

_POSITION_LIMIT: int = 200


def hydrogel_orders(
    snapshot: NormalizedSnapshot,
    position: int,
    timestamp: int,
    params: SSTParams = _DEFAULT_PARAMS,
    skew_strength: float = 1.0,
) -> list[Order]:
    """Generate HYDROGEL orders for one tick.

    ``skew_strength`` controls how aggressively inventory tilts quotes.
    1.0 = one tick per 100-unit position (at limit → max 2-tick skew).
    """
    if snapshot.mid is None:
        return []

    cap = scaled_cap(_POSITION_LIMIT, timestamp)
    fair_value = _skewed_fair(snapshot, position, cap, skew_strength)

    decision: TradingDecision = take_clear_make(
        product=HYDROGEL_PACK,
        fair_value=fair_value,
        snapshot=snapshot,
        position=position,
        position_limit=cap,
        params=params,
    )
    return decision.orders


def _skewed_fair(
    snapshot: NormalizedSnapshot,
    position: int,
    cap: int,
    strength: float,
) -> float:
    """Shift the fair value to skew quotes away from current inventory."""
    mid = snapshot.mid
    if mid is None:
        return 0.0
    if cap <= 0:
        return mid
    # Skew: positive position → lower fair (suppresses bids, lifts asks)
    pos_ratio = position / cap
    skew = -pos_ratio * strength  # in ticks
    return mid + skew

# ========================================================================
# src/strategies/round_3/vev_4000_mm.py
# ========================================================================

"""VEV_4000 synthetic-underlying MM — Plan B + Plan F (sub-intrinsic guard).

VEV_4000 is a deep-ITM call: mid ≈ VELVET − 4000. Spread median 21 ticks.
3-day hedged replay: +7,546. Second alpha after HYDROGEL.

Fair-value construction (hedge-aware):
    hedge_buffer = 0.5 × velvet_spread  (absorbs VELVET spread cost)
    bid_fair = velvet_bid − 4000 − hedge_buffer
    ask_fair = velvet_ask − 4000 + hedge_buffer

Sub-intrinsic ask guard (Plan F, T09):
    ask_floor = max(velvet_bid − 4000, 0) + 1
    our_ask = max(our_ask, ask_floor)

Scanner: if competitor ask < velvet_bid − 4000, buy + hedge. Fires ~1/30K.
"""




_PRODUCT: str = "VEV_4000"
_POSITION_LIMIT: int = 300

_DEFAULT_PARAMS: SSTParams = SSTParams(
    take_width=3.0,
    clear_threshold=0.5,
    clear_width=3.0,
    default_edge=3.0,
    disregard_edge=1.0,
    join_edge=3.0,
    default_quote_size=5,
    max_taker_size=10,
    prevent_adverse=False,
    quote_inside_wall=False,  # use hedge-aware fair, not wall-peg
)

# Hard delta-budget soft cap for this engine (overridden by R3DeltaBudget).
_SOFT_CAP: int = 150
_HARD_CAP: int = 200  # only when delta budget allows


def vev4000_orders(
    vev_snapshot: NormalizedSnapshot,
    velvet_snapshot: NormalizedSnapshot | None,
    position: int,
    timestamp: int,
    delta_remaining: int = 999,
    params: SSTParams = _DEFAULT_PARAMS,
) -> list[Order]:
    """Generate VEV_4000 + sub-intrinsic-scanner orders for one tick.

    ``delta_remaining`` from R3DeltaBudget limits the effective cap.
    Returns VEV_4000 orders only (no VELVET hedge orders — those come
    from the VelvetHedgeInfra component).
    """
    if velvet_snapshot is None:
        return []

    velvet_bid = velvet_snapshot.best_bid
    velvet_ask = velvet_snapshot.best_ask
    if velvet_bid is None or velvet_ask is None:
        return []

    velvet_spread = velvet_ask.price - velvet_bid.price
    hedge_buffer = 0.5 * velvet_spread

    bid_fair = velvet_bid.price - 4000 - hedge_buffer
    ask_fair = velvet_ask.price - 4000 + hedge_buffer
    # Use midpoint of these two fairs as the SST fair value
    fair_value = (bid_fair + ask_fair) / 2.0

    if fair_value <= 0:
        return []

    # Cap: softer when delta budget is tight
    raw_cap = _SOFT_CAP if delta_remaining < 50 else _HARD_CAP
    cap = min(scaled_cap(_POSITION_LIMIT, timestamp), raw_cap)

    decision: TradingDecision = take_clear_make(
        product=_PRODUCT,
        fair_value=fair_value,
        snapshot=vev_snapshot,
        position=position,
        position_limit=cap,
        params=params,
    )

    orders = list(decision.orders)

    # --- Sub-intrinsic ask guard (Plan F / T09) ---
    intrinsic = max(velvet_bid.price - 4000, 0)
    ask_floor = intrinsic + 1
    corrected: list[Order] = []
    for o in orders:
        if o.quantity < 0 and o.price < ask_floor:
            # Raise ask to floor to prevent sub-intrinsic sale
            corrected.append(Order(o.symbol, ask_floor, o.quantity))
        else:
            corrected.append(o)
    orders = corrected

    # --- Sub-intrinsic buy scanner (rare: ~1/30K per strike) ---
    if vev_snapshot.best_ask is not None:
        competitor_ask = vev_snapshot.best_ask.price
        if competitor_ask < intrinsic:
            # Arbitrage: buy voucher + short VELVET (hedge leg added by VelvetHedge)
            buy_qty = min(5, _POSITION_LIMIT - position) if position < _POSITION_LIMIT else 0
            if buy_qty > 0:
                orders.append(Order(_PRODUCT, competitor_ask, buy_qty))

    return orders

# ========================================================================
# src/strategies/round_3/voucher_liquidity.py
# ========================================================================

"""Voucher tiny-liquidity provider — Plan C.

Only K=5400 and K=5500. Join best bid (do not improve). Recycle
inventory by improving ask when long. Guard against corruption and
delta-budget exhaustion.

Expected contribution: ~+150 shells (K=5400 + K=5500 combined).
NOT a P&L engine — inventory absorption at a small acceptable delta cost.

K=5300 is explicitly NOT quoted here (hedge cost > spread capture).
"""





@dataclass(frozen=True)
class VoucherSpec:
    strike: int
    soft_cap: int
    hard_cap: int


_VOUCHER_SPECS: tuple[VoucherSpec, ...] = (
    VoucherSpec(strike=5400, soft_cap=50, hard_cap=100),
    VoucherSpec(strike=5500, soft_cap=100, hard_cap=150),
)

_POSITION_LIMIT: int = 300


def voucher_liquidity_orders(
    snapshots: dict[int, "NormalizedSnapshot"],
    positions: dict[int, int],
    timestamp: int,
    delta_remaining: int = 999,
    corrupted: set[int] | None = None,
) -> list[Order]:
    """Generate tiny-liquidity orders for K=5400 and K=5500.

    ``snapshots``   maps strike → NormalizedSnapshot
    ``positions``   maps strike → current position
    ``delta_remaining`` from R3DeltaBudget (suppress bidding when tight)
    ``corrupted``   set of strikes whose smile is corrupt (from SmileCache)
    """

    corrupted = corrupted or set()
    orders: list[Order] = []

    for spec in _VOUCHER_SPECS:
        k = spec.strike
        symbol = f"VEV_{k}"
        snap: NormalizedSnapshot | None = snapshots.get(k)
        if snap is None:
            continue

        pos = positions.get(k, 0)
        soft_cap = scaled_cap(spec.soft_cap, timestamp)
        hard_cap = scaled_cap(spec.hard_cap, timestamp)

        # Quoting rules
        no_bid = (
            pos >= soft_cap
            or k in corrupted
            or delta_remaining < 10
            or snap.best_bid is None
        )
        no_ask = snap.best_ask is None

        # Bid: join best bid (do not improve)
        if not no_bid:
            bid_price = snap.best_bid.price  # type: ignore[union-attr]
            bid_qty = min(5, hard_cap - pos) if pos < hard_cap else 0
            if bid_qty > 0:
                orders.append(Order(symbol, bid_price, bid_qty))

        # Ask: join or improve (recycle mode when pos >= soft_cap)
        if not no_ask and pos > 0:
            ask_price = snap.best_ask.price  # type: ignore[union-attr]
            if pos >= soft_cap:
                # Improve ask by 1 tick to encourage recycling
                ask_price = max(ask_price - 1, (snap.best_bid.price + 1) if snap.best_bid else ask_price)
            ask_qty = min(5, pos)
            if ask_qty > 0:
                orders.append(Order(symbol, ask_price, -ask_qty))

    return orders

# ========================================================================
# src/strategies/round_3/velvet_hedge.py
# ========================================================================

"""VELVETFRUIT_EXTRACT hedge infrastructure — Plan D.

VELVET is NOT a P&L bucket. Its role: delta-hedge the options complex.
Tight inventory band ±60 (not ±200), aggressive skew toward delta target.

Hedge bands:
    |net_delta| < 40       → passive MM only, no directional intent
    40 ≤ |net_delta| ≤ 120 → skew quotes toward target
    |net_delta| > 120      → cross (take) to restore delta budget
"""




_PRODUCT: str = VELVETFRUIT_EXTRACT
_POSITION_LIMIT: int = 200
_TIGHT_BAND: int = 60  # VELVET is infrastructure; don't warehouse

_PARAMS_PASSIVE: SSTParams = SSTParams(
    take_width=1.0,
    clear_threshold=0.5,
    clear_width=2.0,
    default_edge=2.0,
    disregard_edge=1.0,
    join_edge=2.0,
    default_quote_size=5,
    max_taker_size=10,
    prevent_adverse=False,
)

_PARAMS_CROSS: SSTParams = SSTParams(
    take_width=8.0,   # wide take to cross aggressively
    clear_threshold=0.3,
    clear_width=2.0,
    default_edge=1.0,
    disregard_edge=1.0,
    join_edge=1.0,
    default_quote_size=5,
    max_taker_size=20,
    prevent_adverse=False,
)


def velvet_hedge_orders(
    snapshot: NormalizedSnapshot,
    velvet_position: int,
    net_delta: float,
    timestamp: int,
) -> list[Order]:
    """Generate VELVET orders for one tick.

    ``net_delta`` is the aggregate delta across all option positions
    (from R3DeltaBudget.net_delta). We want to drive this toward 0.

    The target VELVET position is ``−net_delta`` (excluding VELVET itself):
        target_velvet = −Σ(voucher_pos[K] × delta[K]) − vev_4000_pos
    """
    if snapshot.mid is None:
        return []

    cap = min(scaled_cap(_POSITION_LIMIT, timestamp), _TIGHT_BAND)

    # Decide hedge mode from net_delta magnitude.
    abs_delta = abs(net_delta)

    if abs_delta > 120:
        # Cross aggressively to restore budget
        params = _PARAMS_CROSS
    else:
        params = _PARAMS_PASSIVE

    # Fair value: skew toward reducing net delta
    mid = snapshot.mid
    if mid is None:
        return []

    # Skew: if net_delta > 0 we want to sell VELVET (lower fair)
    #       if net_delta < 0 we want to buy VELVET (raise fair)
    if abs_delta >= 40:
        # Skew strength grows from 0 at |delta|=40 to 3.0 ticks at |delta|=120
        skew_magnitude = min(3.0, (abs_delta - 40) / 80.0 * 3.0)
        # net_delta > 0 → too long → lower fair (sell bias)
        direction = -math.copysign(1.0, net_delta)
        fair_value = mid + direction * skew_magnitude
    else:
        fair_value = mid

    if fair_value <= 0:
        return []

    decision = take_clear_make(
        product=_PRODUCT,
        fair_value=fair_value,
        snapshot=snapshot,
        position=velvet_position,
        position_limit=cap,
        params=params,
    )
    return decision.orders

# ========================================================================
# src/strategies/round_3/zero_bid_lottery.py
# ========================================================================

"""Zero-bid lottery for VEV_6000 and VEV_6500 — Plan E.

Place BUY @ 0 on both deep-OTM strikes for full capacity (300 each).
First 10 ticks: probe whether price-0 orders are accepted.
If rejected, disable self. 0-cost fills are exempt from TerminalRamp.

Expected: 0–300 shells if platform accepts and end-of-round FV > 0.
"""



_LOTTERY_STRIKES: tuple[int, ...] = (6000, 6500)
_POSITION_LIMIT: int = 300
_PROBE_TICKS: int = 10


def zero_bid_orders(
    tick_count: int,
    positions: dict[str, int],
    accepted: bool | None,
) -> list[Order]:
    """Generate 0-price buy orders for VEV_6000 and VEV_6500.

    ``tick_count`` — number of ticks elapsed since start (0-indexed).
    ``positions``  — current positions by product symbol.
    ``accepted``   — None = unknown, True = accept confirmed,
                     False = rejected (disable strategy).

    Returns empty list if platform rejected 0-price orders.
    """
    if accepted is False:
        return []

    orders: list[Order] = []
    for k in _LOTTERY_STRIKES:
        symbol = f"VEV_{k}"
        pos = positions.get(symbol, 0)
        remaining = _POSITION_LIMIT - pos
        if remaining > 0:
            orders.append(Order(symbol, 0, remaining))

    return orders


def detect_acceptance(
    tick_count: int,
    order_results: dict[str, list[Order]],
    positions_before: dict[str, int],
    positions_after: dict[str, int],
) -> bool | None:
    """Infer whether 0-price orders were accepted.

    Returns:
        None  — too early / inconclusive
        True  — at least one VEV_6000/6500 position changed (accepted)
        False — probe window elapsed, no change (rejected or no fills)
    """
    if tick_count < _PROBE_TICKS:
        for k in _LOTTERY_STRIKES:
            symbol = f"VEV_{k}"
            if positions_after.get(symbol, 0) > positions_before.get(symbol, 0):
                return True
        return None  # still probing
    # Probe window elapsed with no fills
    for k in _LOTTERY_STRIKES:
        symbol = f"VEV_{k}"
        if positions_after.get(symbol, 0) > 0:
            return True
    return False

# ========================================================================
# src/engines/r3_engine.py
# ========================================================================

"""R3Engine — top-level PersistableEngine for the Round 3 submission.

Owns all R3 products and orchestrates:
  A. HYDROGEL_PACK MM (Plan A)
  B. VEV_4000 synthetic MM + sub-intrinsic guard (Plans B + F)
  C. Voucher tiny-liquidity K=5400 / K=5500 (Plan C)
  D. VELVET hedge infrastructure (Plan D)
  E. Zero-bid lottery VEV_6000 / VEV_6500 (Plan E)
  H. Aggregate delta/gamma budget (Plan H)
  G. Terminal risk ramp (Plan G)
  SmileCache: per-tick IV smile fit for delta estimates + corruption guard

Signal-bus Tier-2 exploits (Plans I-L) are wired in separately and
enabled only after leave-one-day-out validation passes.

This engine is self-contained. The Trader just constructs one instance
and passes it to EngineOrchestrator.
"""



# Strategy helpers


class R3Engine:
    """Orchestrator engine for all R3 products.

    Implements the PersistableEngine protocol (engine_id, owned_products,
    step, to_state, from_state).
    """

    def __init__(self) -> None:
        self._delta_budget = R3DeltaBudget()
        self._smile_cache = SmileCache()
        self._tick_count: int = 0
        self._zero_bid_accepted: bool | None = None
        self._prev_positions: dict[str, int] = {}

    # ========================================================= protocol

    @property
    def engine_id(self) -> str:
        return "r3_engine"

    @property
    def owned_products(self) -> frozenset[str]:
        return ALL_R3_PRODUCTS

    def to_state(self) -> dict:
        return {
            "tick_count": self._tick_count,
            "zero_bid_accepted": self._zero_bid_accepted,
            "delta_budget": self._delta_budget.to_state(),
            "smile_cache": self._smile_cache.snapshot(),
            "prev_positions": dict(self._prev_positions),
        }

    def from_state(self, blob: dict) -> None:
        if not blob:
            return
        try:
            self._tick_count = int(blob.get("tick_count", 0))
            accepted = blob.get("zero_bid_accepted")
            self._zero_bid_accepted = (
                bool(accepted) if accepted is not None else None
            )
            db_blob = blob.get("delta_budget", {})
            if db_blob:
                self._delta_budget.from_state(db_blob)
            sc_blob = blob.get("smile_cache", {})
            if sc_blob:
                self._smile_cache.restore(sc_blob)
            prev = blob.get("prev_positions", {})
            if isinstance(prev, dict):
                self._prev_positions = {str(k): int(v) for k, v in prev.items()}
        except (TypeError, ValueError, KeyError):
            pass  # cold-start on corruption

    # ========================================================= step

    def step(
        self,
        portfolio: PortfolioSnapshot,
        *,
        current_tick: int,
    ) -> EngineStepResult:
        """Emit orders for all R3 products for this tick."""
        ts = current_tick

        # ---- 0. Read snapshots and positions ----
        hydrogel_snap = portfolio.for_product(HYDROGEL_PACK)
        velvet_snap = portfolio.for_product(VELVETFRUIT_EXTRACT)
        vev4000_snap = portfolio.for_product("VEV_4000")

        positions: dict[str, int] = {
            p: portfolio.position_of(p) for p in ALL_R3_PRODUCTS
        }

        # ---- 1. Update smile cache ----
        if velvet_snap is not None and velvet_snap.mid is not None:
            spot = float(velvet_snap.mid)
            strike_mids: dict[int, float] = {}
            for k in VOUCHER_STRIKES:
                vs = portfolio.for_product(f"VEV_{k}")
                if vs is not None and vs.mid is not None:
                    strike_mids[k] = float(vs.mid)
            self._smile_cache.update(ts, spot, strike_mids)

            # Push smile deltas into delta budget
            for k in VOUCHER_STRIKES:
                d = self._smile_cache.delta(k)
                if d is not None:
                    self._delta_budget.set_strike_delta(k, d)
        else:
            spot = None

        # ---- 2. Collect intended orders from each strategy ----
        intended: list[Order] = []

        # A. HYDROGEL MM
        if hydrogel_snap is not None:
            hydrogel_pos = positions.get(HYDROGEL_PACK, 0)
            intended.extend(
                hydrogel_orders(hydrogel_snap, hydrogel_pos, ts)
            )

        # B. VEV_4000 MM + sub-intrinsic guard
        if vev4000_snap is not None and velvet_snap is not None:
            vev4000_pos = positions.get("VEV_4000", 0)
            delta_remaining = self._delta_budget.remaining_capacity(
                ts, positions, spot
            )
            intended.extend(
                vev4000_orders(
                    vev4000_snap,
                    velvet_snap,
                    vev4000_pos,
                    ts,
                    delta_remaining=delta_remaining,
                )
            )

        # C. Voucher tiny-liquidity K=5400, K=5500 — DISABLED
        # LOO validation fails all 3 held-out days (-66, -64, -78).
        # K=5400 net edge = -1.0/fill (spread 0.5 < delta*VELVET_spread*0.5 = 1.5).
        # K=5500 marginal (+0.25/fill, expected ~+150 total). Not worth the delta risk.
        # voucher_liquidity_orders retained in code for future reactivation if market
        # structure changes (wider spread or lower VELVET vol).

        # D. VELVET hedge
        if velvet_snap is not None:
            velvet_pos = positions.get(VELVETFRUIT_EXTRACT, 0)
            net_delta = self._delta_budget.net_delta(positions, spot)
            intended.extend(
                velvet_hedge_orders(velvet_snap, velvet_pos, net_delta, ts)
            )

        # E. Zero-bid lottery (exempt from delta budget — no delta)
        lottery_orders = zero_bid_orders(
            self._tick_count,
            positions,
            self._zero_bid_accepted,
        )
        # We add lottery orders directly (bypass delta budget — 0-cost, no delta)
        lottery_set = {o.symbol for o in lottery_orders}

        # ---- 3. Enforce aggregate delta budget ----
        # Delta budget only applies to non-lottery orders
        non_lottery = [o for o in intended if o.symbol not in lottery_set]
        safe_orders = self._delta_budget.enforce(
            non_lottery, ts, positions, spot
        )
        all_orders = safe_orders + lottery_orders

        # ---- 4. Update acceptance probe ----
        if self._zero_bid_accepted is None and self._tick_count >= 1:
            self._zero_bid_accepted = detect_acceptance(
                self._tick_count,
                {},  # order results not directly available here
                self._prev_positions,
                positions,
            )

        self._prev_positions = dict(positions)
        self._tick_count += 1

        return EngineStepResult(orders=all_orders)

# ========================================================================
# src/engines/r3_factory.py
# ========================================================================

"""R3 submission entry-point factory.

This module is the LAST module in the R3 bundle. It re-defines ``Trader``
so the Prosperity container (which calls ``Trader()`` with no args) gets a
fully-wired R3 Trader: EngineOrchestrator with R3Engine registered.

The bundler strips src-import lines so all names resolve flat; the
``_BaseTrader = Trader`` alias captures the Trader defined earlier in the
bundle before the override.
"""



_R3_CONFIG = EngineConfig(
    products={},
    state_version=1,
    max_trader_data_chars=50_000,
)


class Trader(_BaseTrader):
    """R3 submission Trader. Zero-arg constructor for Prosperity platform."""

    def __init__(self) -> None:
        super().__init__(
            config=_R3_CONFIG,
            orchestrator=EngineOrchestrator([R3Engine()]),
        )
